// Google Apps Script Code for Accounting App
// Deploy this as a Web App with "Anyone" access.

const SPREADSHEET_ID = "1J0wYR-pnMWFVDOU_cA_GxF2WGn86e-nZQ0RP4HJ8Je4"; 
const DATA_SHEET_NAME = "Data_2026";
const CONFIG_SHEET_NAME = "Config";

function doPost(e) {
  const lock = LockService.getScriptLock();
  if (!lock.tryLock(10000)) {
    return createJSONOutput({ status: 'error', message: 'System busy' });
  }

  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    let payload = JSON.parse(e.postData.contents);
    const action = payload.action || 'submit'; // 'submit', 'getConfig', 'updateConfig'

    // 1. Get Config (Secret & Users)
    const config = getConfig(ss);

    // 2. Verify Secret (Except for initial setup check if needed, but let's enforce it)
    // Note: If secret is empty in Config sheet, we might allow it? No, safer to require it.
    if (config.secret && payload.secret !== config.secret) {
      return createJSONOutput({ status: 'error', message: 'Unauthorized: Invalid Secret' });
    }

    // 3. Handle Actions
    if (action === 'getConfig') {
      return createJSONOutput({ 
        status: 'success', 
        users: config.users 
      });
    }

    if (action === 'updateUsers') {
      // Payload: { action: 'updateUsers', users: ['a@g.com', 'b@g.com'] }
      updateUsers(ss, payload.users);
      return createJSONOutput({ status: 'success' });
    }

    if (action === 'submit') {
      // Validate User
      const userEmail = (payload.userEmail || "").trim().toLowerCase();
      if (!config.users.includes(userEmail)) {
        return createJSONOutput({ status: 'error', message: `User '${userEmail}' is not allowed.` });
      }

      // Append Row
      const result = appendRow(ss, payload, userEmail);
      return createJSONOutput(result);
    }

    return createJSONOutput({ status: 'error', message: 'Unknown action' });

  } catch (err) {
    return createJSONOutput({ status: 'error', message: err.toString() });
  } finally {
    lock.releaseLock();
  }
}

// --- Helper Functions ---

function getConfig(ss) {
  let sheet = ss.getSheetByName(CONFIG_SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(CONFIG_SHEET_NAME);
    // Init Config Sheet
    sheet.getRange("A1").setValue("API_SECRET");
    sheet.getRange("B1").setValue("my-secret-888"); // Default
    sheet.getRange("A2").setValue("ALLOWED_USERS");
    sheet.getRange("B2").setValue("stonez56@gmail.com,stonez.chen@gmail.com"); // Default
  }

  const secret = sheet.getRange("B1").getValue().toString();
  const usersStr = sheet.getRange("B2").getValue().toString();
  const users = usersStr.split(',').map(u => u.trim().toLowerCase()).filter(u => u);

  return { secret, users };
}

function updateUsers(ss, newUsers) {
  const sheet = ss.getSheetByName(CONFIG_SHEET_NAME);
  const usersStr = newUsers.join(',');
  sheet.getRange("B2").setValue(usersStr);
}

function appendRow(ss, payload, userEmail) {
  let sheet = ss.getSheetByName(DATA_SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(DATA_SHEET_NAME);
    const headers = [
      "流水號", "日期", "進銷別", "格式代號", "發票號碼", 
      "對方統編", "銷售額", "營業稅額", "總金額", "課稅別", 
      "會計科目", "備註", "紀錄者"
    ];
    sheet.appendRow(headers);
    sheet.setFrozenRows(1);
  }

  const rowData = [
    Utilities.getUuid(),
    payload.date || new Date().toISOString().split('T')[0],
    payload.type,
    payload.formatCode,
    (payload.invoiceNo || "").toUpperCase(),
    payload.taxId || "",
    payload.amount,
    payload.tax,
    payload.total,
    payload.taxType || "1",
    payload.category,
    payload.note || "",
    userEmail
  ];

  sheet.appendRow(rowData);
  return { status: 'success', row: sheet.getLastRow() };
}

function createJSONOutput(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

