/**
 * 台灣營利事業統一編號校驗 (UBN Validation)
 * 1. 8位數字
 * 2. 乘數: 1, 2, 1, 2, 1, 2, 4, 1
 * 3. 乘積之個位與十位相加
 * 4. 總和需為 10 之倍數 (若第7位為7，總和加1後為10之倍數亦可)
 */
export function isValidTaiwanTaxId(taxId: string): boolean {
  if (!/^\d{8}$/.test(taxId)) return false;

  const multipliers = [1, 2, 1, 2, 1, 2, 4, 1];
  let sum = 0;

  const calculateDigitSum = (n: number) => Math.floor(n / 10) + (n % 10);

  for (let i = 0; i < 8; i++) {
    const digit = parseInt(taxId[i]);
    const product = digit * multipliers[i];
    sum += calculateDigitSum(product);
  }

  if (sum % 10 === 0) return true;

  // 特殊情況：第7位是7時，乘積為 4*7=28，加總為 2+8=10
  // 演算法規定此時加總可以取 1 (即 10 的個位數 0 與十位數 1 相加)
  if (taxId[6] === '7' && (sum + 1) % 10 === 0) return true;

  return false;
}

import React, { useRef, useState } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { Camera, Upload, Loader2, Sparkles, X } from 'lucide-react';
import { Button } from './UI';

interface ScannerProps {
  onScanResult: (data: any) => void;
  onClose: () => void;
}

export const Scanner: React.FC<ScannerProps> = ({ onScanResult, onClose }) => {
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const processImage = async (base64Data: string) => {
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          {
            parts: [
              { inlineData: { mimeType: 'image/jpeg', data: base64Data } },
              { text: "這是一張台灣發票（統一發票）。請提取以下資訊並以 JSON 格式回傳：date (YYYY-MM-DD), invoiceNo (2位大寫字母+8位數字), taxId (賣方統編), amount (未稅金額), tax (稅額), total (總額), category (建議會計科目)。如果無法辨識則回傳空值。請嚴格遵守 JSON 格式。" }
            ]
          }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING },
              invoiceNo: { type: Type.STRING },
              taxId: { type: Type.STRING },
              amount: { type: Type.NUMBER },
              tax: { type: Type.NUMBER },
              total: { type: Type.NUMBER },
              category: { type: Type.STRING }
            }
          }
        }
      });

      const result = JSON.parse(response.text || '{}');
      onScanResult(result);
    } catch (error) {
      console.error("AI Scan Error:", error);
      alert("掃描失敗，請手動輸入或再試一次。");
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      processImage(base64);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm">
      <div className="w-full max-w-sm bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-2xl">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-bold flex items-center">
            <Sparkles className="w-5 h-5 mr-2 text-sky-400" />
            AI 智慧掃描
          </h3>
          <button onClick={onClose} className="text-slate-500 hover:text-white">
            <X size={20} />
          </button>
        </div>

        <div className="space-y-4">
          <Button 
            className="w-full h-32 flex-col space-y-2 border-2 border-dashed border-slate-700 bg-slate-800/50 hover:bg-slate-800 hover:border-sky-500"
            onClick={() => fileInputRef.current?.click()}
            isLoading={loading}
          >
            {loading ? (
              <Loader2 className="w-8 h-8 animate-spin text-sky-400" />
            ) : (
              <>
                <Camera className="w-8 h-8 text-sky-400" />
                <span>拍照或上傳發票</span>
              </>
            )}
          </Button>

          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            capture="environment" 
            onChange={handleFileUpload} 
          />

          <p className="text-xs text-slate-500 text-center">
            支援台灣電子發票、三聯式發票照片。<br/>AI 將自動填寫日期、統編及金額。
          </p>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
