};

import React, { useRef, useState } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { Camera, Upload, Loader2, Sparkles, X, ScanLine } from 'lucide-react';
import { Button } from './UI';

interface ScannerProps {
  onScanResult: (data: any) => void;
  onClose: () => void;
}

export const Scanner: React.FC<ScannerProps> = ({ onScanResult, onClose }) => {
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const processImage = async (base64Data: string) => {
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          {
            parts: [
              { inlineData: { mimeType: 'image/jpeg', data: base64Data } },
              { 
                text: `
                You are an expert accountant for a Taiwan one-person company. 
                Analyze this invoice image and extract data strictly following Taiwan VAT regulations.

                Return JSON with these fields:
                - type: "Input" (Expenses/Buying) or "Output" (Sales/Selling). Default to "Input" for receipts.
                - formatCode: Detect based on visual style:
                  * "21": Triplicate Invoice (Input) - B2B, has Tax ID.
                  * "22": Cash Register (Input) - Long strip, MUST have Buyer Tax ID.
                  * "25": Other Receipt (Input) - Taxi, Parking, etc.
                  * "33": Cloud Invoice (Input) - Has 2 QR codes.
                  * "31": Triplicate (Output).
                - date: "YYYY-MM-DD". Convert ROC year (e.g. 115 -> 2026).
                - invoiceNo: 10 chars (2 letters + 8 digits).
                - taxId: Seller's Tax ID (8 digits).
                - amount: Sales Amount (excluding tax).
                - tax: Tax Amount (usually 5% of amount).
                - total: Total Amount (Amount + Tax).
                - category: Suggest one: "進貨成本", "文具用品", "交際費", "差旅費", "租金支出", "水電瓦斯", "郵電費", "修繕費", "廣告費", "勞務費", "交通費", "雜項購置".

                Strictly return only JSON.
                `
              }
            ]
          }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              formatCode: { type: Type.STRING },
              date: { type: Type.STRING },
              invoiceNo: { type: Type.STRING },
              taxId: { type: Type.STRING },
              amount: { type: Type.NUMBER },
              tax: { type: Type.NUMBER },
              total: { type: Type.NUMBER },
              category: { type: Type.STRING }
            }
          }
        }
      });

      const result = JSON.parse(response.text || '{}');
      onScanResult(result);
    } catch (error) {
      console.error("AI Scan Error:", error);
      alert("掃描辨識失敗，請重試或手動輸入。");
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validate size (simple check, < 5MB)
    if (file.size > 5 * 1024 * 1024) {
      alert("圖片過大，請使用小於 5MB 的照片");
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      processImage(base64);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-md animate-in fade-in duration-200">
      <div className="w-full max-w-sm bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-2xl relative overflow-hidden">
        {/* Decorative elements */}
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-sky-500 via-purple-500 to-emerald-500" />

        <div className="flex justify-between items-center mb-8">
          <h3 className="text-lg font-bold flex items-center text-white">
            <ScanLine className="w-5 h-5 mr-2 text-sky-400" />
            AI 智慧憑證掃描
          </h3>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-800 text-slate-400 hover:text-white transition-colors">
            <X size={20} />
          </button>
        </div>

        <div className="space-y-6">
          <div className="relative group cursor-pointer" onClick={() => !loading && fileInputRef.current?.click()}>
            <div className={`
              w-full h-40 rounded-xl border-2 border-dashed transition-all duration-300 flex flex-col items-center justify-center space-y-3
              ${loading 
                ? 'border-sky-500/50 bg-sky-500/5' 
                : 'border-slate-700 bg-slate-800/30 hover:bg-slate-800 hover:border-sky-400 hover:shadow-lg hover:shadow-sky-500/10'
              }
            `}>
              {loading ? (
                <>
                  <Loader2 className="w-10 h-10 animate-spin text-sky-400" />
                  <p className="text-sm text-sky-300 font-medium animate-pulse">正在分析憑證...</p>
                </>
              ) : (
                <>
                  <div className="p-3 rounded-full bg-slate-800 group-hover:bg-sky-500 group-hover:text-white transition-colors text-sky-400">
                    <Camera className="w-8 h-8" />
                  </div>
                  <div className="text-center">
                    <p className="text-sm font-medium text-slate-200">點擊拍照或上傳</p>
                    <p className="text-xs text-slate-500 mt-1">支援 JPG, PNG</p>
                  </div>
                </>
              )}
            </div>
          </div>

          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            capture="environment" 
            onChange={handleFileUpload} 
          />

          <div className="bg-slate-800/50 rounded-lg p-3 text-xs text-slate-400 leading-relaxed border border-slate-700/50">
            <p className="flex items-start gap-2">
              <Sparkles className="w-3 h-3 mt-0.5 text-yellow-400 shrink-0" />
              AI 將自動辨識：進銷別、格式代號 (21/25/33等)、日期、統編、金額與建議科目。
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Save, 
  RotateCcw, 
  FileText, 
  Hash, 
  DollarSign, 
  Calendar,
  Sparkles,
  CheckCircle2
} from 'lucide-react';
import { 
  InvoiceType, 
  TaxType, 
  InvoiceFormState, 
  AppConfig, 
  ApiResponse 
} from '../types';
import { 
  INITIAL_FORM_STATE, 
  FORMAT_CODE_OPTIONS, 
  CATEGORY_OPTIONS, 
  TAX_TYPE_OPTIONS 
} from '../constants';
import { Card, Input, Select, Button, Label } from './UI';
import { isValidTaiwanTaxId } from '../utils/validation';
import { Scanner } from './Scanner';

interface InvoiceFormProps {
  config: AppConfig;
  onLogout: () => void;
}

export const InvoiceForm: React.FC<InvoiceFormProps> = ({ config, onLogout }) => {
  const [formData, setFormData] = useState<InvoiceFormState>(INITIAL_FORM_STATE);
  const [loading, setLoading] = useState(false);
  const [showScanner, setShowScanner] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  // Auto-calculate Tax (SOP: Sales x 5%)
  // We perform this calculation whenever amount changes to strictly follow the checklist.
  const calculateTotals = useCallback(() => {
    if (formData.amount === '' || formData.taxType !== TaxType.TAXABLE) return;

    const amount = Number(formData.amount);
    // Standard Taiwan VAT calculation: Round(Amount * 0.05)
    const tax = Math.round(amount * 0.05);
    const total = amount + tax;

    setFormData(prev => ({ ...prev, tax, total }));
  }, [formData.amount, formData.taxType]);

  useEffect(() => {
    if (formData.amount !== '' && formData.taxType === TaxType.TAXABLE) {
       calculateTotals();
    } else if (formData.taxType === TaxType.ZERO_RATE || formData.taxType === TaxType.TAX_FREE) {
        const amount = Number(formData.amount || 0);
        setFormData(prev => ({ ...prev, tax: 0, total: amount }));
    }
  }, [formData.amount, formData.taxType, calculateTotals]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newType = e.target.value as InvoiceType;
    const firstFormatCode = FORMAT_CODE_OPTIONS[newType][0].value;
    setFormData(prev => ({ 
      ...prev, 
      type: newType, 
      formatCode: firstFormatCode 
    }));
  };

  const handleScanResult = (data: any) => {
    // 1. Determine Type (Input/Output)
    const newType = (data.type === 'Output') ? InvoiceType.OUTPUT : InvoiceType.INPUT;

    // 2. Determine Format Code - Verify it exists in options, otherwise fallback
    let newFormatCode = data.formatCode;
    const validCodes = FORMAT_CODE_OPTIONS[newType].map(o => o.value);
    if (!validCodes.includes(newFormatCode)) {
      newFormatCode = validCodes[0];
    }

    setFormData(prev => ({
      ...prev,
      type: newType,
      formatCode: newFormatCode,
      date: data.date || prev.date,
      invoiceNo: data.invoiceNo || prev.invoiceNo,
      taxId: data.taxId || prev.taxId,
      amount: data.amount || prev.amount,
      // Note: We intentionally don't set 'tax'/'total' here because the useEffect 
      // will immediately recalculate them based on 'amount' to ensure 5% accuracy.
      category: data.category || prev.category,
    }));

    setShowScanner(false);
    setMessage({ type: 'success', text: 'AI 辨識完成！請核對金額與科目。' });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);

    if (!formData.amount) {
      setMessage({ type: 'error', text: '請輸入銷售額' });
      setLoading(false);
      return;
    }

    const payload = {
      action: 'submit',
      secret: config.apiSecret,
      userEmail: config.userEmail,
      ...formData,
      amount: Number(formData.amount),
      tax: Number(formData.tax),
      total: Number(formData.total),
    };

    try {
      const response = await fetch(config.scriptUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify(payload),
      });

      const result: ApiResponse = await response.json();

      if (result.status === 'success') {
        setMessage({ type: 'success', text: `成功錄入! (Row: ${result.row})` });
        // Keep Date and Type for convenience, reset others
        setFormData(prev => ({
          ...INITIAL_FORM_STATE,
          date: prev.date,
          type: prev.type,
          formatCode: prev.formatCode,
        }));
      } else {
        throw new Error(result.message || 'Unknown error');
      }
    } catch (error: any) {
      console.error(error);
      setMessage({ type: 'error', text: `Error: ${error.message}` });
    } finally {
      setLoading(false);
    }
  };

  const isTaxIdValid = formData.taxId === '' || isValidTaiwanTaxId(formData.taxId);

  return (
    <div className="max-w-4xl mx-auto pb-24">
      {showScanner && <Scanner onScanResult={handleScanResult} onClose={() => setShowScanner(false)} />}

      <div className="flex justify-between items-center mb-6">
        <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
              新增憑證
              <span className="text-xs font-normal px-2 py-0.5 rounded bg-slate-800 text-slate-400 border border-slate-700">2026 帳期</span>
            </h2>
            <p className="text-slate-400 text-sm">{config.userEmail}</p>
        </div>
        <Button variant="ghost" onClick={onLogout} size="sm">登出</Button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Section 1: Classification */}
          <Card className="p-6 space-y-4">
            <div className="flex justify-between items-center mb-2">
              <h3 className="text-sky-400 font-semibold text-sm uppercase tracking-wider flex items-center">
                <FileText className="w-4 h-4 mr-2" />
                憑證分類
              </h3>
              <Button 
                type="button" 
                variant="secondary" 
                size="sm" 
                className="h-8 text-xs bg-sky-500/10 hover:bg-sky-500/20 text-sky-400 border-sky-500/20"
                onClick={() => setShowScanner(true)}
              >
                <Sparkles size={14} className="mr-1.5" />
                AI 掃描
              </Button>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <Select
                id="type"
                name="type"
                label="進銷別"
                value={formData.type}
                onChange={handleTypeChange}
                options={[
                  { value: InvoiceType.INPUT, label: '進項 (支出)' },
                  { value: InvoiceType.OUTPUT, label: '銷項 (收入)' },
                ]}
              />
              <Input
                id="date"
                name="date"
                type="date"
                label="日期"
                value={formData.date}
                onChange={handleChange}
                required
                icon={Calendar}
              />
            </div>

            <Select
              id="formatCode"
              name="formatCode"
              label="格式代號 (依 SOP 選擇)"
              value={formData.formatCode}
              onChange={handleChange}
              options={FORMAT_CODE_OPTIONS[formData.type]}
            />

            <div className="grid grid-cols-2 gap-4">
              <Input
                id="invoiceNo"
                name="invoiceNo"
                label="發票號碼"
                placeholder="AA12345678"
                value={formData.invoiceNo}
                onChange={(e) => setFormData(prev => ({...prev, invoiceNo: e.target.value.toUpperCase()}))}
                maxLength={10}
                icon={Hash}
              />
              <div className="relative">
                <Input
                  id="taxId"
                  name="taxId"
                  label="對方統編"
                  placeholder="8位數字"
                  value={formData.taxId}
                  onChange={handleChange}
                  maxLength={8}
                  error={!isTaxIdValid ? "統編邏輯錯誤" : ""}
                />
                 {isTaxIdValid && formData.taxId.length === 8 && (
                   <CheckCircle2 className="absolute top-9 right-3 text-emerald-500 w-4 h-4 animate-in zoom-in" />
                )}
              </div>
            </div>
          </Card>

          {/* Section 2: Amounts */}
          <Card className="p-6 space-y-4">
            <h3 className="text-emerald-400 font-semibold text-sm uppercase tracking-wider mb-2 flex items-center">
              <DollarSign className="w-4 h-4 mr-2" />
              金額明細
            </h3>

             <Select
              id="taxType"
              name="taxType"
              label="課稅別"
              value={formData.taxType}
              onChange={handleChange}
              options={TAX_TYPE_OPTIONS}
            />

            <div className="space-y-4">
              <Input
                id="amount"
                name="amount"
                type="number"
                label="銷售額 (未稅)"
                placeholder="0"
                value={formData.amount}
                onChange={handleChange}
                required
                icon={DollarSign}
                className="font-mono text-xl tracking-tight"
              />

              <div className="grid grid-cols-2 gap-4">
                 <Input
                  id="tax"
                  name="tax"
                  type="number"
                  label="營業稅額 (5%)"
                  value={formData.tax}
                  onChange={handleChange}
                  readOnly={formData.taxType === TaxType.TAXABLE}
                  className={formData.taxType === TaxType.TAXABLE ? "bg-slate-900/50 text-slate-400 cursor-not-allowed" : ""}
                />
                 <Input
                  id="total"
                  name="total"
                  type="number"
                  label="總金額 (含稅)"
                  value={formData.total}
                  readOnly
                  className="bg-slate-900/50 font-bold text-emerald-400 cursor-not-allowed"
                />
              </div>
            </div>
          </Card>

          {/* Section 3: Details */}
          <Card className="p-6 space-y-4 md:col-span-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                     <h3 className="text-slate-400 font-semibold text-sm uppercase tracking-wider mb-2">
                      帳務歸屬
                    </h3>
                    <div className="relative">
                        <Label htmlFor="category">會計科目</Label>
                        <select
                            id="category"
                            name="category"
                            value={formData.category}
                            onChange={handleChange}
                            className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2.5 pl-3 pr-8 text-slate-100 focus:outline-none focus:ring-2 focus:ring-sky-500 mt-1"
                        >
                            {CATEGORY_OPTIONS.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                    </div>
                </div>

                <div className="space-y-4">
                    <h3 className="text-slate-400 font-semibold text-sm uppercase tracking-wider mb-2">
                      備註說明
                    </h3>
                    <div>
                        <Label htmlFor="note">備註</Label>
                        <input
                            id="note"
                            name="note"
                            value={formData.note}
                            onChange={handleChange}
                            placeholder="如：購買電腦、固定資產..."
                            className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2.5 px-3 text-slate-100 focus:outline-none focus:ring-2 focus:ring-sky-500 mt-1"
                        />
                    </div>
                </div>
            </div>
          </Card>
        </div>

        {/* Floating Action Bar */}
        <div className="fixed bottom-0 left-0 right-0 p-4 bg-slate-950/80 backdrop-blur-md border-t border-slate-800 z-40 safe-area-bottom">
            <div className="max-w-4xl mx-auto flex flex-col md:flex-row items-center gap-4">
                <Button 
                    type="submit" 
                    className="w-full md:w-auto md:flex-1 py-3 text-lg font-bold shadow-lg shadow-sky-900/20"
                    isLoading={loading}
                    icon={Save}
                >
                    確認送出
                </Button>

                <Button 
                    type="button" 
                    variant="ghost" 
                    onClick={() => setFormData(INITIAL_FORM_STATE)}
                    icon={RotateCcw}
                    disabled={loading}
                    className="w-full md:w-auto"
                >
                    重置
                </Button>

                {message && (
                    <div className={`w-full md:w-auto flex-1 px-4 py-2 rounded-lg text-sm font-medium flex items-center animate-in fade-in slide-in-from-bottom-2 ${
                        message.type === 'success' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'bg-rose-500/10 text-rose-400 border border-rose-500/20'
                    }`}>
                        {message.text}
                    </div>
                )}
            </div>
        </div>
      </form>
    </div>
  );
};

import React from 'react';
import { LucideIcon } from 'lucide-react';

