import React, { useState, useEffect, useCallback } from 'react';
import { 
  Save, 
  RotateCcw, 
  FileText, 
  Hash, 
  DollarSign, 
  Calendar,
  Sparkles,
  CheckCircle2,
  AlertTriangle
} from 'lucide-react';
import { 
  InvoiceType, 
  TaxType, 
  InvoiceFormState, 
  AppConfig, 
  ApiResponse 
} from '../types';
import { 
  INITIAL_FORM_STATE, 
  FORMAT_CODE_OPTIONS, 
  CATEGORY_GROUPS, 
  TAX_TYPE_OPTIONS 
} from '../constants';
import { Card, Input, Select, Button, Label } from './UI';
import { isValidTaiwanTaxId } from '../utils/validation';
import { Scanner } from './Scanner';

interface InvoiceFormProps {
  config: AppConfig;
  onLogout: () => void;
}

export const InvoiceForm: React.FC<InvoiceFormProps> = ({ config, onLogout }) => {
  const [formData, setFormData] = useState<InvoiceFormState>(INITIAL_FORM_STATE);
  const [loading, setLoading] = useState(false);
  const [showScanner, setShowScanner] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string; detail?: string } | null>(null);

  // Auto-calculate Tax (SOP: Sales x 5%)
  const calculateTotals = useCallback(() => {
    if (formData.amount === '' || formData.taxType !== TaxType.TAXABLE) return;

    const amount = Number(formData.amount);
    const tax = Math.round(amount * 0.05);
    const total = amount + tax;

    setFormData(prev => ({ ...prev, tax, total }));
  }, [formData.amount, formData.taxType]);

  useEffect(() => {
    if (formData.amount !== '' && formData.taxType === TaxType.TAXABLE) {
       calculateTotals();
    } else if (formData.taxType === TaxType.ZERO_RATE || formData.taxType === TaxType.TAX_FREE) {
        const amount = Number(formData.amount || 0);
        setFormData(prev => ({ ...prev, tax: 0, total: amount }));
    }
  }, [formData.amount, formData.taxType, calculateTotals]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newType = e.target.value as InvoiceType;
    const firstFormatCode = FORMAT_CODE_OPTIONS[newType][0].value;
    setFormData(prev => ({ 
      ...prev, 
      type: newType, 
      formatCode: firstFormatCode 
    }));
  };

  const handleScanResult = (data: any) => {
    const newType = (data.type === 'Output') ? InvoiceType.OUTPUT : InvoiceType.INPUT;

    let newFormatCode = data.formatCode;
    const validCodes = FORMAT_CODE_OPTIONS[newType].map(o => o.value);
    if (!validCodes.includes(newFormatCode)) {
      newFormatCode = validCodes[0];
    }

    setFormData(prev => ({
      ...prev,
      type: newType,
      formatCode: newFormatCode,
      date: data.date || prev.date,
      invoiceNo: data.invoiceNo || prev.invoiceNo,
      taxId: data.taxId || prev.taxId,
      amount: data.amount || prev.amount,
      category: data.category || prev.category,
    }));

    setShowScanner(false);
    setMessage({ type: 'success', text: 'AI 辨識完成！請核對金額與科目。' });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);

    if (!formData.amount) {
      setMessage({ type: 'error', text: '請輸入銷售額' });
      setLoading(false);
      return;
    }

    if (!formData.category) {
      setMessage({ type: 'error', text: '請選擇會計科目' });
      setLoading(false);
      return;
    }

    const payload = {
      action: 'submit',
      secret: config.apiSecret,
      userEmail: config.userEmail,
      ...formData,
      amount: Number(formData.amount),
      tax: Number(formData.tax),
      total: Number(formData.total),
    };

    try {
      // NOTE: 'no-cors' mode would hide errors but also hide the response.
      // We use 'cors' mode. If this fails, it's a GAS deployment permission issue.
      const response = await fetch(config.scriptUrl, {
        method: 'POST',
        mode: 'cors', 
        headers: { 
          'Content-Type': 'text/plain;charset=utf-8' 
        },
        body: JSON.stringify(payload),
        redirect: 'follow',
      });

      if (!response.ok) {
        throw new Error(`Server responded with ${response.status}`);
      }

      const result: ApiResponse = await response.json();

      if (result.status === 'success') {
        setMessage({ type: 'success', text: `成功錄入! (Row: ${result.row})` });
        setFormData(prev => ({
          ...INITIAL_FORM_STATE,
          date: prev.date,
          type: prev.type,
          formatCode: prev.formatCode,
        }));
      } else {
        throw new Error(result.message || 'Unknown error');
      }
    } catch (error: any) {
      console.error("Submission Error Details:", error);
      let errorMsg = error.message;
      let errorDetail = "";

      if (errorMsg.includes("Failed to fetch") || errorMsg.includes("NetworkError")) {
        errorMsg = "連線失敗 (CORS Error)";
        errorDetail = "請確認 Google Apps Script 部署設定：執行身分=「我 (Me)」，存取權限=「任何人 (Anyone)」。設定錯誤會導致瀏覽器阻擋連線。";
      }

      setMessage({ type: 'error', text: errorMsg, detail: errorDetail });
    } finally {
      setLoading(false);
    }
  };

  const isTaxIdValid = formData.taxId === '' || isValidTaiwanTaxId(formData.taxId);

  return (
    <div className="max-w-4xl mx-auto pb-24">
      {showScanner && <Scanner onScanResult={handleScanResult} onClose={() => setShowScanner(false)} />}

      <div className="flex justify-between items-center mb-6">
        <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
              新增憑證
              <span className="text-xs font-normal px-2 py-0.5 rounded bg-slate-800 text-slate-400 border border-slate-700">2026 帳期</span>
            </h2>
            <p className="text-slate-400 text-sm">{config.userEmail}</p>
        </div>
        <Button variant="ghost" onClick={onLogout} size="sm">登出</Button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <Card className="p-6 space-y-4">
            <div className="flex justify-between items-center mb-2">
              <h3 className="text-sky-400 font-semibold text-sm uppercase tracking-wider flex items-center">
                <FileText className="w-4 h-4 mr-2" />
                憑證分類
              </h3>
              <Button 
                type="button" 
                variant="secondary" 
                size="sm" 
                className="h-8 text-xs bg-sky-500/10 hover:bg-sky-500/20 text-sky-400 border-sky-500/20"
                onClick={() => setShowScanner(true)}
              >
                <Sparkles size={14} className="mr-1.5" />
                AI 掃描
              </Button>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <Select
                id="type"
                name="type"
                label="進銷別"
                value={formData.type}
                onChange={handleTypeChange}
                options={[
                  { value: InvoiceType.INPUT, label: '進項 (支出)' },
                  { value: InvoiceType.OUTPUT, label: '銷項 (收入)' },
                ]}
              />
              <Input
                id="date"
                name="date"
                type="date"
                label="日期"
                value={formData.date}
                onChange={handleChange}
                required
                icon={Calendar}
              />
            </div>

            <Select
              id="formatCode"
              name="formatCode"
              label="格式代號 (依 SOP 選擇)"
              value={formData.formatCode}
              onChange={handleChange}
              options={FORMAT_CODE_OPTIONS[formData.type]}
            />

            <div className="grid grid-cols-2 gap-4">
              <Input
                id="invoiceNo"
                name="invoiceNo"
                label="發票號碼"
                placeholder="AA12345678"
                value={formData.invoiceNo}
                onChange={(e) => setFormData(prev => ({...prev, invoiceNo: e.target.value.toUpperCase()}))}
                maxLength={10}
                required
                icon={Hash}
              />
              <div className="relative">
                <Input
                  id="taxId"
                  name="taxId"
                  label="對方統編"
                  placeholder="8位數字"
                  value={formData.taxId}
                  onChange={handleChange}
                  maxLength={8}
                  error={!isTaxIdValid ? "統編邏輯錯誤" : ""}
                />
                 {isTaxIdValid && formData.taxId.length === 8 && (
                   <CheckCircle2 className="absolute top-9 right-3 text-emerald-500 w-4 h-4 animate-in zoom-in" />
                )}
              </div>
            </div>
          </Card>

          <Card className="p-6 space-y-4">
            <h3 className="text-emerald-400 font-semibold text-sm uppercase tracking-wider mb-2 flex items-center">
              <DollarSign className="w-4 h-4 mr-2" />
              金額明細
            </h3>

             <Select
              id="taxType"
              name="taxType"
              label="課稅別"
              value={formData.taxType}
              onChange={handleChange}
              options={TAX_TYPE_OPTIONS}
            />

            <div className="space-y-4">
              <Input
                id="amount"
                name="amount"
                type="number"
                label="銷售額 (未稅)"
                placeholder="0"
                value={formData.amount}
                onChange={handleChange}
                required
                icon={DollarSign}
                className="font-mono text-xl tracking-tight"
              />

              <div className="grid grid-cols-2 gap-4">
                 <Input
                  id="tax"
                  name="tax"
                  type="number"
                  label="營業稅額 (5%)"
                  value={formData.tax}
                  onChange={handleChange}
                  readOnly={formData.taxType === TaxType.TAXABLE}
                  className={formData.taxType === TaxType.TAXABLE ? "bg-slate-900/50 text-slate-400 cursor-not-allowed" : ""}
                />
                 <Input
                  id="total"
                  name="total"
                  type="number"
                  label="總金額 (含稅)"
                  value={formData.total}
                  readOnly
                  className="bg-slate-900/50 font-bold text-emerald-400 cursor-not-allowed"
                />
              </div>
            </div>
          </Card>

          <Card className="p-6 space-y-4 md:col-span-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                     <h3 className="text-slate-400 font-semibold text-sm uppercase tracking-wider mb-2">
                      帳務歸屬
                    </h3>
                    <div className="relative">
                        <Label htmlFor="category" required>會計科目</Label>
                        <select
                            id="category"
                            name="category"
                            value={formData.category}
                            onChange={handleChange}
                            required
                            className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2.5 pl-3 pr-8 text-slate-100 focus:outline-none focus:ring-2 focus:ring-sky-500 mt-1 appearance-none"
                        >
                            <option value="" disabled>-- 請選擇類別 --</option>
                            {CATEGORY_GROUPS.map((group) => (
                              <optgroup key={group.groupLabel} label={group.groupLabel}>
                                {group.items.map((item) => (
                                  <option key={item.value} value={item.value}>
                                    {item.label}
                                  </option>
                                ))}
                              </optgroup>
                            ))}
                        </select>
                        <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none text-slate-500 mt-6">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" />
                          </svg>
                        </div>
                    </div>
                </div>

                <div className="space-y-4">
                    <h3 className="text-slate-400 font-semibold text-sm uppercase tracking-wider mb-2">
                      備註說明
                    </h3>
                    <div>
                        <Label htmlFor="note">備註</Label>
                        <input
                            id="note"
                            name="note"
                            value={formData.note}
                            onChange={handleChange}
                            placeholder="如：購買電腦、固定資產..."
                            className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2.5 px-3 text-slate-100 focus:outline-none focus:ring-2 focus:ring-sky-500 mt-1"
                        />
                    </div>
                </div>
            </div>
          </Card>
        </div>

        <div className="fixed bottom-0 left-0 right-0 p-4 bg-slate-950/80 backdrop-blur-md border-t border-slate-800 z-40 safe-area-bottom">
            <div className="max-w-4xl mx-auto flex flex-col md:flex-row items-center gap-4">
                <Button 
                    type="submit" 
                    className="w-full md:w-auto md:flex-1 py-3 text-lg font-bold shadow-lg shadow-sky-900/20"
                    isLoading={loading}
                    icon={Save}
                >
                    確認送出
                </Button>

                <Button 
                    type="button" 
                    variant="ghost" 
                    onClick={() => setFormData(INITIAL_FORM_STATE)}
                    icon={RotateCcw}
                    disabled={loading}
                    className="w-full md:w-auto"
                >
                    重置
                </Button>

                {message && (
                    <div className={`w-full md:w-auto flex-1 px-4 py-2 rounded-lg text-sm font-medium flex flex-col justify-center animate-in fade-in slide-in-from-bottom-2 ${
                        message.type === 'success' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'bg-rose-500/10 text-rose-400 border border-rose-500/20'
                    }`}>
                        <div className="flex items-center">
                            {message.type === 'error' && <AlertTriangle className="w-4 h-4 mr-2" />}
                            <span>{message.text}</span>
                        </div>
                        {message.detail && (
                            <div className="text-xs mt-1 text-rose-300 opacity-80 pl-6">
                                {message.detail}
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
      </form>
    </div>
  );
};

