                              <optgroup key={group.groupLabel} label={group.groupLabel} className="bg-slate-900">
                                {group.items.map((item) => (
                                  <option key={item.value} value={item.value}>
                                    {item.label}
                                  </option>
                                ))}
                              </optgroup>
                            ))}
