import React, { useRef, useState, useEffect } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { Camera, Loader2, Sparkles, X, ScanLine, Upload } from 'lucide-react';
import { FLATTENED_CATEGORY_VALUES } from '../constants.ts';

interface ScannerProps {
  onScanResult: (data: any) => void;
  onClose: () => void;
}

export const Scanner: React.FC<ScannerProps> = ({ onScanResult, onClose }) => {
  const [loading, setLoading] = useState(false);
  const [cameraActive, setCameraActive] = useState(false);
  const [cameraError, setCameraError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Clean up stream on unmount
  useEffect(() => {
    return () => {
      stopCamera();
    };
  }, []);

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
    setCameraActive(false);
    setCameraError(null);
  };

  const startCamera = async () => {
    try {
      setCameraError(null);
      // Request high resolution for better OCR
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          facingMode: 'environment',
          width: { ideal: 1920 },
          height: { ideal: 1080 } 
        } 
      });

      setCameraActive(true);

      // Delay attaching stream slightly to ensure DOM is ready
      setTimeout(async () => {
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          try {
             // Explicitly play to avoid autoplay policy issues
             await videoRef.current.play();
          } catch (e) {
             console.error("Video play error:", e);
          }
        }
      }, 100);

    } catch (err: any) {
      console.error("Camera access error:", err);
      setCameraError("無法存取相機，請檢查瀏覽器權限或使用 HTTPS。");
    }
  };

  const captureImage = () => {
    if (!videoRef.current || !canvasRef.current) return;

    const video = videoRef.current;
    const canvas = canvasRef.current;

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;

    const context = canvas.getContext('2d');
    if (context) {
      context.drawImage(video, 0, 0, canvas.width, canvas.height);
      const base64Data = canvas.toDataURL('image/jpeg', 0.8).split(',')[1];
      stopCamera(); // Stop camera after capture
      processImage(base64Data);
    }
  };

  const processImage = async (base64Data: string) => {
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const categoryList = FLATTENED_CATEGORY_VALUES.join('", "');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          {
            parts: [
              { inlineData: { mimeType: 'image/jpeg', data: base64Data } },
              { 
                text: `
                You are an expert accountant for a Taiwan one-person company. 
                Analyze this invoice image and extract data strictly following Taiwan VAT regulations.

                Return JSON with these fields:
                - type: "Input" (Expenses/Buying) or "Output" (Sales/Selling). Default to "Input".
                - formatCode: Detect based on visual style:
                  * "21": Triplicate Invoice (Input) - B2B, has Tax ID.
                  * "22": Cash Register (Input) - Long strip, MUST have Buyer Tax ID.
                  * "25": Other Receipt (Input) - Taxi, Parking, etc.
                  * "33": Cloud Invoice (Input) - Has 2 QR codes.
                  * "31": Triplicate (Output).
                - date: "YYYY-MM-DD". Convert ROC year (e.g. 115 -> 2026).
                - invoiceNo: 10 chars (2 letters + 8 digits).
                - taxId: Seller's Tax ID (8 digits).
                - amount: Sales Amount (excluding tax).
                - tax: Tax Amount (usually 5% of amount).
                - total: Total Amount (Amount + Tax).
                - category: Suggest exactly one from this list: ["${categoryList}"]. 
                  Rule:
                  - Computer/Phone/HardDrive < 80k -> "雜項購置-硬體"
                  - Software/SaaS -> "各項耗竭及攤提"
                  - Stationery -> "文具用品"
                  - Taxi/HSR/Flight -> "旅費-交通"
                  - Internet/Phone Bill -> "郵電費"
                  - Food/Drinks -> "交際費" (if generic) or "伙食費" (if employee meal).

                Strictly return only JSON.
                `
              }
            ]
          }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              formatCode: { type: Type.STRING },
              date: { type: Type.STRING },
              invoiceNo: { type: Type.STRING },
              taxId: { type: Type.STRING },
              amount: { type: Type.NUMBER },
              tax: { type: Type.NUMBER },
              total: { type: Type.NUMBER },
              category: { type: Type.STRING }
            }
          }
        }
      });

      const result = JSON.parse(response.text || '{}');
      onScanResult(result);
    } catch (error) {
      console.error("AI Scan Error:", error);
      alert("掃描辨識失敗，請重試或手動輸入。");
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      alert("圖片過大，請使用小於 5MB 的照片");
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      processImage(base64);
    };
    reader.readAsDataURL(file);
  };

  return (
    <>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-md animate-in fade-in duration-200">
        <div className="w-full max-w-sm bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-2xl relative overflow-hidden">
          {/* Helper Canvas for capture (hidden) */}
          <canvas ref={canvasRef} className="hidden" />

          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-sky-500 via-purple-500 to-emerald-500" />

          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-bold flex items-center text-white">
              <ScanLine className="w-5 h-5 mr-2 text-sky-400" />
              AI 智慧憑證掃描
            </h3>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-800 text-slate-400 hover:text-white transition-colors">
              <X size={20} />
            </button>
          </div>

          <div className="space-y-4">
            {loading ? (
               <div className="w-full h-48 rounded-xl border-2 border-dashed border-sky-500/50 bg-sky-500/5 flex flex-col items-center justify-center space-y-3">
                  <Loader2 className="w-10 h-10 animate-spin text-sky-400" />
                  <p className="text-sm text-sky-300 font-medium animate-pulse">正在分析憑證...</p>
               </div>
            ) : (
              <div className="grid grid-cols-2 gap-4">
                  <button
                      onClick={startCamera}
                      className="flex flex-col items-center justify-center h-32 rounded-xl bg-slate-800 border border-slate-700 hover:bg-slate-700 hover:border-sky-500/50 transition-all group"
                  >
                      <div className="p-3 rounded-full bg-slate-900 group-hover:bg-sky-500 group-hover:text-white text-sky-400 mb-2 transition-colors">
                          <Camera className="w-6 h-6" />
                      </div>
                      <span className="text-sm font-medium text-slate-300">開啟相機</span>
                  </button>

                  <button
                      onClick={() => fileInputRef.current?.click()}
                      className="flex flex-col items-center justify-center h-32 rounded-xl bg-slate-800 border border-slate-700 hover:bg-slate-700 hover:border-emerald-500/50 transition-all group"
                  >
                      <div className="p-3 rounded-full bg-slate-900 group-hover:bg-emerald-500 group-hover:text-white text-emerald-400 mb-2 transition-colors">
                          <Upload className="w-6 h-6" />
                      </div>
                      <span className="text-sm font-medium text-slate-300">上傳圖片</span>
                  </button>
              </div>
            )}

            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileUpload} 
            />

            {cameraError && (
                <div className="text-xs text-rose-400 bg-rose-500/10 p-2 rounded text-center">
                    {cameraError}
                </div>
            )}

            <div className="bg-slate-800/50 rounded-lg p-3 text-xs text-slate-400 leading-relaxed border border-slate-700/50">
              <p className="flex items-start gap-2">
                <Sparkles className="w-3 h-3 mt-0.5 text-yellow-400 shrink-0" />
                AI 將自動辨識：進銷別、格式代號、日期、統編、金額與建議科目。
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* Full Screen Camera Overlay */}
      {cameraActive && (
        <div className="fixed inset-0 z-[100] bg-black flex flex-col animate-in fade-in duration-300">
          <div className="absolute top-0 left-0 right-0 p-6 z-20 flex justify-between items-start bg-gradient-to-b from-black/80 to-transparent pb-12">
             <div className="px-4 py-2 bg-black/40 backdrop-blur-md rounded-full text-white text-sm font-medium border border-white/10">
                拍攝收據 / 發票
             </div>
             <button 
               onClick={stopCamera} 
               className="p-3 bg-black/40 hover:bg-slate-800 text-white rounded-full backdrop-blur-md transition-all border border-white/10"
             >
               <X size={24} />
             </button>
          </div>

          <div className="relative flex-1 bg-black overflow-hidden flex items-center justify-center">
              <video 
                ref={videoRef} 
                autoPlay 
                playsInline 
                muted
                className="absolute w-full h-full object-cover"
              />

              {/* Visual Guide Box */}
              <div className="relative w-[85%] aspect-[3/4] max-w-md border-2 border-white/30 rounded-2xl shadow-[0_0_0_9999px_rgba(0,0,0,0.5)] pointer-events-none">
                  <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-sky-500 -mt-0.5 -ml-0.5 rounded-tl-xl" />
                  <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-sky-500 -mt-0.5 -mr-0.5 rounded-tr-xl" />
                  <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-sky-500 -mb-0.5 -ml-0.5 rounded-bl-xl" />
                  <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-sky-500 -mb-0.5 -mr-0.5 rounded-br-xl" />

                  <div className="absolute inset-0 flex items-center justify-center opacity-30">
                     <ScanLine className="w-16 h-16 text-white animate-pulse" />
                  </div>
              </div>
          </div>

          <div className="h-32 bg-black flex items-center justify-center relative z-20 pt-2 pb-8">
               <button 
                  onClick={captureImage}
                  className="group relative w-20 h-20 flex items-center justify-center touch-manipulation"
               >
                   <div className="absolute inset-0 bg-white rounded-full opacity-20 group-hover:scale-110 transition-transform duration-300" />
                   <div className="relative w-16 h-16 bg-white rounded-full border-[3px] border-slate-900 ring-4 ring-white shadow-xl group-active:scale-95 transition-transform duration-100" />
               </button>
          </div>
        </div>
      )}
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { AuthForm } from './components/AuthForm.tsx';
import { InvoiceForm } from './components/InvoiceForm.tsx';
import { AppConfig } from './types.ts';

export default function App() {
  const [config, setConfig] = useState<AppConfig | null>(null);

  useEffect(() => {
    // Attempt to load from localStorage to persist login
    const savedConfig = localStorage.getItem('app_config');
    if (savedConfig) {
      try {
        const parsed = JSON.parse(savedConfig);
        // Basic validation to ensure the saved config is useful
        if (parsed.scriptUrl && parsed.userEmail && parsed.apiSecret) {
            setConfig(parsed);
        }
      } catch (e) {
        localStorage.removeItem('app_config');
      }
    }
  }, []);

  const handleLogin = (newConfig: AppConfig) => {
    setConfig(newConfig);
    localStorage.setItem('app_config', JSON.stringify(newConfig));
  };

  const handleLogout = () => {
    setConfig(null);
    localStorage.removeItem('app_config');
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans selection:bg-sky-500/30">
      {/* Background Gradient Mesh */}
      <div className="fixed inset-0 z-0 pointer-events-none">
         <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] rounded-full bg-sky-900/10 blur-[100px]" />
         <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] rounded-full bg-emerald-900/10 blur-[100px]" />
      </div>

      <div className="relative z-10 p-4 md:p-8">
        {!config ? (
          <AuthForm onLogin={handleLogin} />
        ) : (
          <InvoiceForm config={config} onLogout={handleLogout} />
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Save, 
  RotateCcw, 
  FileText, 
  Hash, 
  DollarSign, 
  Calendar,
  Sparkles,
  CheckCircle2,
  AlertTriangle,
  WifiOff,
  ExternalLink,
  Table2,
  History
} from 'lucide-react';
import { 
  InvoiceType, 
  TaxType, 
  InvoiceFormState, 
  AppConfig, 
  ApiResponse 
} from '../types.ts';
import { 
  INITIAL_FORM_STATE, 
  FORMAT_CODE_OPTIONS, 
  CATEGORY_GROUPS, 
  TAX_TYPE_OPTIONS 
} from '../constants.ts';
import { Card, Input, Select, Button, Label } from './UI.tsx';
import { isValidTaiwanTaxId } from '../utils/validation.ts';
import { Scanner } from './Scanner.tsx';

interface InvoiceFormProps {
  config: AppConfig;
  onLogout: () => void;
}

const LAST_SCAN_KEY = 'last_scanned_invoice';

export const InvoiceForm: React.FC<InvoiceFormProps> = ({ config, onLogout }) => {
  const [formData, setFormData] = useState<InvoiceFormState>(INITIAL_FORM_STATE);
  const [loading, setLoading] = useState(false);
  const [showScanner, setShowScanner] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string; detail?: React.ReactNode } | null>(null);
  const [hasLastScan, setHasLastScan] = useState(false);

  useEffect(() => {
    // Check if there is a saved scan
    const saved = localStorage.getItem(LAST_SCAN_KEY);
    if (saved) {
      setHasLastScan(true);
    }
  }, []);

  const calculateTotals = useCallback(() => {
    if (formData.amount === '' || formData.taxType !== TaxType.TAXABLE) return;
    const amount = Number(formData.amount);
    const tax = Math.round(amount * 0.05);
    const total = amount + tax;
    setFormData(prev => ({ ...prev, tax, total }));
  }, [formData.amount, formData.taxType]);

  useEffect(() => {
    if (formData.amount !== '' && formData.taxType === TaxType.TAXABLE) {
       calculateTotals();
    } else if (formData.taxType === TaxType.ZERO_RATE || formData.taxType === TaxType.TAX_FREE) {
        const amount = Number(formData.amount || 0);
        setFormData(prev => ({ ...prev, tax: 0, total: amount }));
    }
  }, [formData.amount, formData.taxType, calculateTotals]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newType = e.target.value as InvoiceType;
    const firstFormatCode = FORMAT_CODE_OPTIONS[newType][0].value;
    setFormData(prev => ({ 
      ...prev, 
      type: newType, 
      formatCode: firstFormatCode 
    }));
  };

  const populateFormData = (data: any) => {
    const newType = (data.type === 'Output') ? InvoiceType.OUTPUT : InvoiceType.INPUT;
    let newFormatCode = data.formatCode;
    const validCodes = FORMAT_CODE_OPTIONS[newType].map(o => o.value);
    if (!validCodes.includes(newFormatCode)) {
      newFormatCode = validCodes[0];
    }
    setFormData(prev => ({
      ...prev,
      type: newType,
      formatCode: newFormatCode,
      date: data.date || prev.date,
      invoiceNo: data.invoiceNo || prev.invoiceNo,
      taxId: data.taxId || prev.taxId,
      amount: data.amount || prev.amount,
      category: data.category || prev.category,
    }));
  };

  const handleScanResult = (data: any) => {
    // Save to local storage for testing
    localStorage.setItem(LAST_SCAN_KEY, JSON.stringify(data));
    setHasLastScan(true);

    populateFormData(data);
    setShowScanner(false);
    setMessage({ type: 'success', text: 'AI 辨識完成！請核對金額與科目。' });
  };

  const restoreLastScan = () => {
    try {
      const saved = localStorage.getItem(LAST_SCAN_KEY);
      if (saved) {
        const data = JSON.parse(saved);
        populateFormData(data);
        setMessage({ type: 'success', text: '已載入上一次的掃描資料。' });
      }
    } catch (e) {
      console.error("Failed to restore scan", e);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);

    // Validation
    if (!formData.amount) {
      setMessage({ type: 'error', text: '請輸入銷售額' });
      setLoading(false);
      return;
    }
    if (!formData.category) {
      setMessage({ type: 'error', text: '請選擇會計科目' });
      setLoading(false);
      return;
    }

    // Validate Tax ID for Triplicate Invoices (21, 31)
    const isTriplicate = ['21', '31'].includes(formData.formatCode);
    if (isTriplicate && !formData.taxId) {
        setMessage({ type: 'error', text: '三聯式發票必須輸入統編 (Tax ID)' });
        setLoading(false);
        return;
    }
    if (formData.taxId && !isValidTaiwanTaxId(formData.taxId)) {
        setMessage({ type: 'error', text: '統編格式錯誤', detail: '請檢查 8 碼統編是否正確' });
        setLoading(false);
        return;
    }

    const payload = {
      action: 'submit',
      secret: config.apiSecret,
      userEmail: config.userEmail,
      ...formData,
      amount: Number(formData.amount),
      tax: Number(formData.tax),
      total: Number(formData.total),
    };

    try {
      const response = await fetch(config.scriptUrl, {
        method: 'POST',
        mode: 'cors',
        headers: { 
          'Content-Type': 'text/plain;charset=utf-8' 
        },
        body: JSON.stringify(payload),
        redirect: 'follow',
      });

      if (!response.ok) {
        throw new Error(`伺服器回應錯誤: ${response.status}`);
      }

      const text = await response.text();
      let result: ApiResponse;

      try {
        result = JSON.parse(text);
      } catch (e) {
        console.error("Non-JSON response:", text);
        throw new Error("伺服器回傳格式錯誤 (非 JSON)");
      }

      if (result.status === 'success') {
        setMessage({ type: 'success', text: `成功錄入! (Row: ${result.row})` });
        setFormData(prev => ({
          ...INITIAL_FORM_STATE,
          date: prev.date,
          type: prev.type,
          formatCode: prev.formatCode,
        }));
      } else {
        throw new Error(result.message || 'Unknown error');
      }
    } catch (error: any) {
      console.error("Submission Error Details:", error);
      let errorMsg = error.message;
      let errorDetail: React.ReactNode = "";

      if (errorMsg.includes("Failed to fetch") || errorMsg.includes("NetworkError")) {
        errorMsg = "連線被拒 (CORS Error)";
        errorDetail = (
          <div className="space-y-1">
            <p>這通常是因為 Google Apps Script 權限設定不正確。</p>
            <p className="font-bold underline">請檢查 Apps Script 部署設定：</p>
            <ul className="list-disc list-inside">
              <li>執行身分 (Execute as): <strong>Me (我)</strong></li>
              <li>存取權限 (Who has access): <strong>Anyone (任何人)</strong></li>
            </ul>
          </div>
        );
      } else if (errorMsg.includes("Invalid Secret")) {
         errorDetail = (
           <div className="space-y-1">
             <p>您輸入的 API 密鑰 (Secret) 不正確。</p>
             <p>請檢查 Google Sheet <strong>「Config」</strong> 分頁中的 <strong>API_SECRET</strong>。</p>
             <p>如果使用開發模式，請確認登入資訊。</p>
           </div>
         );
      }

      setMessage({ type: 'error', text: errorMsg, detail: errorDetail });
    } finally {
      setLoading(false);
    }
  };

  const isTaxIdValid = formData.taxId === '' || isValidTaiwanTaxId(formData.taxId);

  return (
    <div className="max-w-4xl mx-auto pb-24">
      {showScanner && <Scanner onScanResult={handleScanResult} onClose={() => setShowScanner(false)} />}

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
              新增憑證
              <span className="text-xs font-normal px-2 py-0.5 rounded bg-slate-800 text-slate-400 border border-slate-700">2026 帳期</span>
            </h2>
            <p className="text-slate-400 text-sm">{config.userEmail}</p>
        </div>
        <div className="flex items-center gap-2 w-full md:w-auto">
          {config.sheetUrl && (
            <a 
              href={config.sheetUrl} 
              target="_blank" 
              rel="noopener noreferrer"
              className="flex-1 md:flex-none inline-flex items-center justify-center px-3 py-1.5 text-sm font-medium text-sky-400 bg-sky-950/50 border border-sky-900/50 rounded-lg hover:bg-sky-900/50 transition-colors"
            >
              <Table2 size={14} className="mr-2" />
