import React, { useState, useEffect } from 'react';
import { Key, Mail, ShieldCheck, WifiOff, CheckSquare, HelpCircle } from 'lucide-react';
import { AppConfig } from '../types.ts';
import { Card, Input, Button } from './UI.tsx';
import { APPS_SCRIPT_URL } from '../constants.ts';

interface AuthFormProps {
  onLogin: (config: AppConfig) => void;
}

const CACHE_KEY = 'auth_form_preference';

export const AuthForm: React.FC<AuthFormProps> = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [secret, setSecret] = useState('');
  const [rememberMe, setRememberMe] = useState(true);
  const [error, setError] = useState<{ text: string; detail?: React.ReactNode } | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const cached = localStorage.getItem(CACHE_KEY);
    if (cached) {
      try {
        const { mail, remember } = JSON.parse(cached);
        if (remember && mail) {
          setEmail(mail);
          setRememberMe(true);
        }
      } catch (e) {
        // Ignore parse error
      }
    }
  }, []);

  const verifyAndLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);

    if (!email || !secret) {
      setError({ text: '請填寫所有欄位' });
      setLoading(false);
      return;
    }

    try {
      const payload = { action: 'getConfig', secret: secret.trim() };

      const response = await fetch(APPS_SCRIPT_URL, {
        method: 'POST',
        mode: 'cors',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify(payload),
        redirect: 'follow',
      });

      if (!response.ok) {
        throw new Error(`伺服器回應錯誤: ${response.status}`);
      }

      const text = await response.text();
      let result;
      try {
        result = JSON.parse(text);
      } catch (e) {
        throw new Error("伺服器回傳非 JSON 格式");
      }

      if (result.status === 'success') {
        const allowedUsers = result.users || [];
        if (!allowedUsers.includes(email.trim().toLowerCase())) {
          setError({ text: `權限錯誤`, detail: `使用者 '${email}' 不在允許名單中。` });
        } else {
          // Handle Remember Me caching (Email only)
          if (rememberMe) {
            localStorage.setItem(CACHE_KEY, JSON.stringify({
              mail: email.trim(),
              remember: true
            }));
          } else {
            localStorage.removeItem(CACHE_KEY);
          }

          onLogin({
            userEmail: email.trim(),
            apiSecret: secret.trim(),
            scriptUrl: APPS_SCRIPT_URL,
          });
        }
      } else {
        setError({ text: '驗證失敗', detail: result.message || '請檢查 API URL 或 Secret 是否正確' });
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      let errorMsg = err.message;
      let errorDetail: React.ReactNode = "請確認 Apps Script 已部署為 Web App 並設為「任何人」皆可存取。";

      if (errorMsg.includes("Failed to fetch") || errorMsg.includes("NetworkError")) {
        errorMsg = "連線被拒 (CORS Error)";
        errorDetail = (
          <div className="space-y-1 mt-1 text-xs text-rose-300/90">
             <p className="font-bold underline">請檢查 Apps Script 部署設定：</p>
             <ul className="list-disc list-inside">
               <li>執行身分 (Execute as): <strong>Me (我)</strong></li>
               <li>存取權限 (Who has access): <strong>Anyone (任何人)</strong></li>
               <li>請確認 <code>constants.ts</code> 中的 <code>APPS_SCRIPT_URL</code> 正確。</li>
             </ul>
          </div>
        );
      }

      setError({ text: errorMsg, detail: errorDetail });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-slate-950">
      <div className="w-full max-w-md">
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-slate-900 border border-slate-800 mb-4 shadow-lg">
            <ShieldCheck className="w-8 h-8 text-sky-500" />
          </div>
          <h1 className="text-2xl font-bold text-white tracking-tight">One-Person Accounting</h1>
          <p className="text-slate-400 mt-2 text-sm">一人公司記帳系統 v2026</p>
        </div>

        <Card className="p-6 md:p-8">
          <form onSubmit={verifyAndLogin} className="space-y-5">
            <Input
              id="email"
              label="電子信箱 (User Email)"
              type="email"
              placeholder="your-email@gmail.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              icon={Mail}
              required
            />

            <div>
                <Input
                id="secret"
                label="API 密鑰 (Secret)"
                type="password"
                placeholder="請輸入 Config 分頁設定的 Secret"
                value={secret}
                onChange={(e) => setSecret(e.target.value)}
                icon={Key}
                required
                />
                <div className="mt-2 flex items-start gap-2 text-xs text-slate-500 bg-slate-900/50 p-2 rounded">
                    <HelpCircle className="w-4 h-4 shrink-0 mt-0.5" />
                    <p>
                        請輸入您 Google Sheet <strong>「Config」</strong> 分頁中設定的密碼 (通常在 B1 儲存格)。
                        <br/>
                        <span className="opacity-70">應用程式需要此金鑰才能讀取與寫入您的試算表。</span>
                    </p>
                </div>
            </div>

            <div className="flex items-center space-x-2 pt-2">
                <div className="relative flex items-center">
                    <input
                        id="remember"
                        type="checkbox"
                        checked={rememberMe}
                        onChange={(e) => setRememberMe(e.target.checked)}
                        className="peer h-4 w-4 cursor-pointer appearance-none rounded border border-slate-600 bg-slate-900 checked:border-sky-500 checked:bg-sky-500 transition-all"
                    />
                    <CheckSquare className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-3 h-3 text-white opacity-0 peer-checked:opacity-100 pointer-events-none" />
                </div>
                <label htmlFor="remember" className="text-sm text-slate-400 cursor-pointer select-none hover:text-slate-300">
                    記住信箱 (Remember Me)
                </label>
            </div>

            {error && (
               <div className="bg-rose-500/10 border border-rose-500/20 text-rose-400 px-4 py-3 rounded-lg text-sm flex flex-col">
                <div className="flex items-center font-bold">
                    <WifiOff className="w-4 h-4 mr-2" />
                    {error.text}
                </div>
                {error.detail && <div className="mt-1 pl-6">{error.detail}</div>}
              </div>
            )}

            <Button type="submit" className="w-full py-3" isLoading={loading}>
              驗證並登入
            </Button>
          </form>
        </Card>
      </div>
    </div>
  );
};

