This is a classic "permissions vs. deployment" conflict. Here is exactly what happened and how to fix it:

1.  **Error 1 (Permission):** When we changed the code to `getActiveSpreadsheet()`, the script needed **new permissions** that hadn't been granted yet. The Web App failed because the script (running as "You") wasn't authorized to touch the sheet *via the script*.
2.  **Error 2 (CORS):** You changed "Execute as" to "User accessing the web app". **This breaks the app.** Our React app talks to Google via a background request (`fetch`). If you require the "User" to execute it, Google blocks the request waiting for a login screen that the React app cannot show (CORS error).

### **The Solution**

You must revert the deployment setting to **"Me"**, but you must **Authorize** the script manually first.

#### **Step 1: Update Google Apps Script (Copy & Paste this)**

I have added a `setup()` function. **You must run this function inside the editor once.**

```javascript
// Google Apps Script - Code.gs
const DATA_SHEET_NAME = "Data_2026";
const CONFIG_SHEET_NAME = "Config";

// --- IMPORTANT: RUN THIS FUNCTION ONCE IN THE EDITOR ---
// Click the dropdown menu at the top, select "setup", and click "Run".
// This forces the permission dialog to appear.
function setup() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  console.log("Authorization successful. Sheet Name: " + ss.getName());
  getConfig(ss); // Test reading config
}

function doPost(e) {
  const lock = LockService.getScriptLock();
  if (!lock.tryLock(10000)) return createJSONOutput({ status: 'error', message: 'System busy' });

  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();

    // Parse Payload
    let payload = {};
    try {
      payload = JSON.parse(e.postData.contents);
    } catch (parseError) {
      return createJSONOutput({ status: 'error', message: 'Invalid JSON payload' });
    }

    const action = payload.action || 'submit'; 

    // 1. Get Config
    const config = getConfig(ss);

    // 2. Verify Secret
    const inputSecret = (payload.secret || "").toString().trim();
    const storedSecret = (config.secret || "").toString().trim();

    if (storedSecret && inputSecret !== storedSecret) {
      return createJSONOutput({ status: 'error', message: 'Unauthorized: Invalid Secret' });
    }

    // 3. Handle Actions
    if (action === 'getConfig') {
      return createJSONOutput({ status: 'success', users: config.users });
    }

    if (action === 'submit') {
      const userEmail = (payload.userEmail || "").trim().toLowerCase();
      if (!config.users.includes(userEmail)) {
        return createJSONOutput({ status: 'error', message: `User '${userEmail}' is not allowed.` });
      }
      const result = appendRow(ss, payload, userEmail);
      return createJSONOutput(result);
    }

    return createJSONOutput({ status: 'error', message: 'Unknown action' });

  } catch (err) {
    return createJSONOutput({ status: 'error', message: err.toString() });
  } finally {
    lock.releaseLock();
  }
}

function getConfig(ss) {
  let sheet = ss.getSheetByName(CONFIG_SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(CONFIG_SHEET_NAME);
    sheet.getRange("A1").setValue("API_SECRET");
    sheet.getRange("B1").setValue("my-secret-888");
    sheet.getRange("A2").setValue("ALLOWED_USERS");
    sheet.getRange("B2").setValue("stonez56@gmail.com,stonez.chen@gmail.com");
  }
  const secret = sheet.getRange("B1").getValue();
  const usersStr = sheet.getRange("B2").getValue();
  const users = (usersStr || "").toString().split(',').map(u => u.trim().toLowerCase()).filter(u => u);
  return { secret, users };
}

function appendRow(ss, payload, userEmail) {
  let sheet = ss.getSheetByName(DATA_SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(DATA_SHEET_NAME);
    // Add Headers if new
    sheet.appendRow(["流水號", "日期", "進銷別", "格式代號", "發票號碼", "對方統編", "銷售額", "營業稅額", "總金額", "課稅別", "會計科目", "備註", "紀錄者"]);
  }

  const rowData = [
    Utilities.getUuid(),
    payload.date,
    payload.type,
    payload.formatCode,
    (payload.invoiceNo || "").toUpperCase(),
    payload.taxId,
    payload.amount,
    payload.tax,
    payload.total,
    payload.taxType,
    payload.category,
    payload.note,
    userEmail
  ];

  sheet.appendRow(rowData);
  return { status: 'success', row: sheet.getLastRow() };
}

function createJSONOutput(data) {
  return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
}
```

#### **Step 2: The Critical Fix Sequence**

1.  **Paste** the code above into your Apps Script editor.
2.  **Select `setup`** from the function dropdown at the top.
3.  **Click "Run"**.
4.  **Accept Permissions:** Google will ask "Review Permissions". Click it, select your account, (if unsafe warning appears: click Advanced -> Go to ... (unsafe)), and click **Allow**.
    *   *This fixes Error #1.*
5.  **Deploy:**
    *   Click **Deploy** -> **Manage Deployments**.
    *   Click **Edit** (Pencil).
    *   **Version:** New version (Important!).
    *   **Execute as:** **Me** (Important!).
    *   **Who has access:** **Anyone** (Important!).
    *   Click **Deploy**.

