import React, { useState, useEffect, useCallback } from 'react';
import { 
  Save, 
  RotateCcw, 
  FileText, 
  Hash, 
  DollarSign, 
  Calendar,
  Sparkles,
  CheckCircle2,
  AlertTriangle,
  WifiOff,
  ExternalLink,
  Table2,
  History,
  ShieldAlert
} from 'lucide-react';
import { 
  InvoiceType, 
  TaxType, 
  InvoiceFormState, 
  AppConfig, 
  ApiResponse 
} from '../types.ts';
import { 
  INITIAL_FORM_STATE, 
  FORMAT_CODE_OPTIONS, 
  CATEGORY_GROUPS, 
  TAX_TYPE_OPTIONS 
} from '../constants.ts';
import { Card, Input, Select, Button, Label } from './UI.tsx';
import { isValidTaiwanTaxId } from '../utils/validation.ts';
import { Scanner } from './Scanner.tsx';

interface InvoiceFormProps {
  config: AppConfig;
  onLogout: () => void;
}

const LAST_SCAN_KEY = 'last_scanned_invoice';
const RISKY_CATEGORIES = ['伙食費', '交際費', '職工福利'];

export const InvoiceForm: React.FC<InvoiceFormProps> = ({ config, onLogout }) => {
  const [formData, setFormData] = useState<InvoiceFormState>(INITIAL_FORM_STATE);
  const [loading, setLoading] = useState(false);
  const [showScanner, setShowScanner] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string; detail?: React.ReactNode } | null>(null);
  const [hasLastScan, setHasLastScan] = useState(false);
  const [isTaxManuallyEdited, setIsTaxManuallyEdited] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem(LAST_SCAN_KEY);
    if (saved) {
      setHasLastScan(true);
    }
  }, []);

  const calculateTotals = useCallback(() => {
    // Stop auto-calc if tax was manually set to 0 (to allow non-deductible logic)
    if (isTaxManuallyEdited) return;

    if (formData.amount === '' || formData.taxType !== TaxType.TAXABLE) return;
    const amount = Number(formData.amount);
    const tax = Math.round(amount * 0.05);
    const total = amount + tax;

    setFormData(prev => {
        if (prev.tax === tax && prev.total === total) return prev;
        return { ...prev, tax, total };
    });
  }, [formData.amount, formData.taxType, isTaxManuallyEdited]);

  useEffect(() => {
    if (formData.amount !== '' && formData.taxType === TaxType.TAXABLE) {
       calculateTotals();
    } else if (formData.taxType === TaxType.ZERO_RATE || formData.taxType === TaxType.TAX_FREE) {
        const amount = Number(formData.amount || 0);
        setFormData(prev => ({ ...prev, tax: 0, total: amount }));
    }
  }, [formData.amount, formData.taxType, calculateTotals]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;

    // Reset manual tax edit flag if user changes base amount
    if (name === 'amount') {
      setIsTaxManuallyEdited(false);
    }

    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleTaxChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setIsTaxManuallyEdited(true);
    setFormData(prev => ({ ...prev, tax: Number(e.target.value) }));
  };

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newType = e.target.value as InvoiceType;
    const firstFormatCode = FORMAT_CODE_OPTIONS[newType][0].value;
    setFormData(prev => ({ 
      ...prev, 
      type: newType, 
      formatCode: firstFormatCode 
    }));
  };

  const makeTaxNonDeductible = () => {
    // Expert Logic: Merge Tax into Sales Amount (Cost), Set Tax to 0.
    const currentTotal = Number(formData.total || 0);
    setFormData(prev => ({
        ...prev,
        amount: currentTotal, // The cost is now the full price
        tax: 0,
        taxType: TaxType.TAXABLE // Keep as taxable so we know it had tax, but amount is 0
    }));
    setIsTaxManuallyEdited(true);
  };

  const populateFormData = (data: any) => {
    console.log("Populating Form Data:", data);

    // Robust Type Detection
    const typeStr = (data.type || '').toLowerCase();
    const newType = (typeStr.includes('output') || typeStr.includes('sales')) 
        ? InvoiceType.OUTPUT 
        : InvoiceType.INPUT;

    // Robust Format Code
    let newFormatCode = data.formatCode;
    const validCodes = FORMAT_CODE_OPTIONS[newType].map(o => o.value);
    if (!validCodes.includes(newFormatCode)) {
      // Default fallback
      newFormatCode = validCodes[0]; 
      // Intelligent fallback for Input: If TaxID exists, prefer 25 (Electronic) over 21 (Triplicate) per expert advice
      if (newType === InvoiceType.INPUT && data.taxId && FORMAT_CODE_OPTIONS[InvoiceType.INPUT].some(o => o.value === '25')) {
          newFormatCode = '25';
      }
    }

    let newDate = data.date || '';
    newDate = newDate.replace(/\//g, '-');

    const parseNumber = (val: any) => {
        if (typeof val === 'number') return val;
        if (typeof val === 'string') {
            const num = parseFloat(val.replace(/,/g, ''));
            return isNaN(num) ? '' : num;
        }
        return '';
    };

    setFormData(prev => ({
      ...prev,
      type: newType,
      formatCode: newFormatCode,
      date: newDate || prev.date,
      invoiceNo: data.invoiceNo || prev.invoiceNo,
      taxId: data.taxId || prev.taxId,
      amount: parseNumber(data.amount),
      tax: parseNumber(data.tax),
      total: parseNumber(data.total),
      category: data.category || prev.category,
      note: data.note || prev.note || '',
    }));
    setIsTaxManuallyEdited(false);
  };

  const handleScanResult = (data: any) => {
    localStorage.setItem(LAST_SCAN_KEY, JSON.stringify(data));
    setHasLastScan(true);

    populateFormData(data);
    setShowScanner(false);

    const amountFound = data.amount ? `金額 $${data.amount}` : '未偵測到金額';
    setMessage({ 
        type: 'success', 
        text: `AI 辨識完成！`, 
        detail: `已填入：${amountFound}、${data.category || '無建議科目'}。請務必核對。` 
    });
  };

  const restoreLastScan = () => {
    try {
      const saved = localStorage.getItem(LAST_SCAN_KEY);
      if (saved) {
        const data = JSON.parse(saved);
        populateFormData(data);
        setMessage({ type: 'success', text: '已載入上一次的掃描資料。' });
      }
    } catch (e) {
      console.error("Failed to restore scan", e);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);

    // Validation
    if (!formData.amount) {
      setMessage({ type: 'error', text: '請輸入銷售額' });
      setLoading(false);
      return;
    }
    if (!formData.category) {
      setMessage({ type: 'error', text: '請選擇會計科目' });
      setLoading(false);
      return;
    }

    const isTriplicate = ['21', '31'].includes(formData.formatCode);
    if (isTriplicate && !formData.taxId) {
        setMessage({ type: 'error', text: '三聯式發票必須輸入統編 (Tax ID)' });
        setLoading(false);
        return;
    }
    if (formData.taxId && !isValidTaiwanTaxId(formData.taxId)) {
        setMessage({ type: 'error', text: '統編格式錯誤', detail: '請檢查 8 碼統編是否正確' });
        setLoading(false);
        return;
    }

    // Mapping for Google Sheet
    const TYPE_MAPPING = {
      [InvoiceType.INPUT]: '進項 (支出)',
      [InvoiceType.OUTPUT]: '銷項 (收入)',
    };

    const TAX_TYPE_LABEL_MAP: Record<string, string> = {
        '1': '1 - 應稅', 
        '2': '2 - 零稅率', 
        '3': '3 - 免稅'
    };

    // Correct 1-to-1 Mapping to match the Sheet columns
    const payload = {
      action: 'submit',
      secret: config.apiSecret,
      userEmail: config.userEmail,
      date: formData.date,
      type: TYPE_MAPPING[formData.type], 
      formatCode: formData.formatCode,
      invoiceNo: formData.invoiceNo,
      taxId: formData.taxId,
      amount: Number(formData.amount),
      tax: Number(formData.tax),
      total: Number(formData.total),
      taxType: TAX_TYPE_LABEL_MAP[formData.taxType],
      category: formData.category,
      note: formData.note,
    };

    try {
      const response = await fetch(config.scriptUrl, {
        method: 'POST',
        mode: 'cors',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify(payload),
        redirect: 'follow',
      });

      if (!response.ok) {
        throw new Error(`伺服器回應錯誤: ${response.status}`);
      }

      const text = await response.text();
      let result: ApiResponse;
      try {
        result = JSON.parse(text);
      } catch (e) {
        throw new Error("伺服器回傳格式錯誤 (非 JSON)");
      }

      if (result.status === 'success') {
        setMessage({ type: 'success', text: `成功錄入! (Row: ${result.row})` });
        setFormData(prev => ({
          ...INITIAL_FORM_STATE,
          date: prev.date,
          type: prev.type,
          formatCode: prev.formatCode,
        }));
        setIsTaxManuallyEdited(false);
      } else {
        throw new Error(result.message || 'Unknown error');
      }
    } catch (error: any) {
      console.error("Submission Error:", error);
      setMessage({ type: 'error', text: error.message });
    } finally {
      setLoading(false);
    }
  };

  const isTaxIdValid = formData.taxId === '' || isValidTaiwanTaxId(formData.taxId);
  const isRiskyCategory = RISKY_CATEGORIES.some(c => formData.category.includes(c));

  return (
    <div className="max-w-4xl mx-auto pb-24">
      {showScanner && <Scanner onScanResult={handleScanResult} onClose={() => setShowScanner(false)} />}

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
              新增憑證
              <span className="text-xs font-normal px-2 py-0.5 rounded bg-slate-800 text-slate-400 border border-slate-700">2026 帳期</span>
            </h2>
            <p className="text-slate-400 text-sm">{config.userEmail}</p>
        </div>
        <div className="flex items-center gap-2 w-full md:w-auto">
          {config.sheetUrl && (
            <a 
              href={config.sheetUrl} 
              target="_blank" 
              rel="noopener noreferrer"
              className="flex-1 md:flex-none inline-flex items-center justify-center px-3 py-1.5 text-sm font-medium text-sky-400 bg-sky-950/50 border border-sky-900/50 rounded-lg hover:bg-sky-900/50 transition-colors"
            >
              <Table2 size={14} className="mr-2" />
              查看報表
              <ExternalLink size={12} className="ml-1 opacity-50" />
            </a>
          )}
          <Button variant="ghost" onClick={onLogout} size="sm" className="flex-1 md:flex-none">登出</Button>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <Card className="p-6 space-y-4">
            <div className="flex justify-between items-center mb-2">
              <h3 className="text-sky-400 font-semibold text-sm uppercase tracking-wider flex items-center">
                <FileText className="w-4 h-4 mr-2" />
                憑證分類
              </h3>
              <div className="flex gap-2">
                {hasLastScan && (
                   <Button 
                    type="button" 
                    variant="ghost" 
                    size="sm" 
                    className="h-8 text-xs text-slate-400 hover:text-white"
                    onClick={restoreLastScan}
                    title="載入上一次掃描的資料"
                  >
                    <History size={14} className="mr-1.5" />
                    載入上次
                  </Button>
                )}
                <Button 
                  type="button" 
                  variant="secondary" 
                  size="sm" 
                  className="h-8 text-xs bg-sky-500/10 hover:bg-sky-500/20 text-sky-400 border-sky-500/20"
                  onClick={() => setShowScanner(true)}
                >
                  <Sparkles size={14} className="mr-1.5" />
                  AI 掃描
                </Button>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <Select
                id="type"
                name="type"
                label="進銷別"
                value={formData.type}
                onChange={handleTypeChange}
                options={[
                  { value: InvoiceType.INPUT, label: '進項 (支出)' },
                  { value: InvoiceType.OUTPUT, label: '銷項 (收入)' },
                ]}
              />
              <Input
                id="date"
                name="date"
                type="date"
                label="日期"
                value={formData.date}
                onChange={handleChange}
                required
                icon={Calendar}
              />
            </div>

            <Select
              id="formatCode"
              name="formatCode"
              label="格式代號"
              value={formData.formatCode}
              onChange={handleChange}
              options={FORMAT_CODE_OPTIONS[formData.type]}
            />

            <div className="grid grid-cols-2 gap-4">
              <Input
                id="invoiceNo"
                name="invoiceNo"
                label="發票號碼"
                placeholder="AA12345678"
                value={formData.invoiceNo}
                onChange={(e) => setFormData(prev => ({...prev, invoiceNo: e.target.value.toUpperCase()}))}
                maxLength={10}
                required
                icon={Hash}
              />
              <div className="relative">
                <Input
                  id="taxId"
                  name="taxId"
                  label="對方統編"
                  placeholder="8位數字"
                  value={formData.taxId}
                  onChange={handleChange}
                  maxLength={8}
                  error={!isTaxIdValid ? "統編邏輯錯誤" : ""}
                  required={['21', '31'].includes(formData.formatCode)}
                />
                 {isTaxIdValid && formData.taxId.length === 8 && (
                   <CheckCircle2 className="absolute top-9 right-3 text-emerald-500 w-4 h-4 animate-in zoom-in" />
                )}
              </div>
            </div>
          </Card>

          <Card className="p-6 space-y-4">
            <h3 className="text-emerald-400 font-semibold text-sm uppercase tracking-wider mb-2 flex items-center">
              <DollarSign className="w-4 h-4 mr-2" />
              金額明細
            </h3>

             <Select
              id="taxType"
              name="taxType"
              label="課稅別"
              value={formData.taxType}
              onChange={handleChange}
              options={TAX_TYPE_OPTIONS}
            />

            <div className="space-y-4">
              <Input
                id="amount"
                name="amount"
                type="number"
                label="銷售額 (未稅)"
                placeholder="0"
                value={formData.amount}
                onChange={handleChange}
                required
                icon={DollarSign}
                className="font-mono text-xl tracking-tight"
              />

              <div className="grid grid-cols-2 gap-4">
                 <Input
                  id="tax"
                  name="tax"
                  type="number"
                  label="營業稅額 (5%)"
                  value={formData.tax}
                  onChange={handleTaxChange}
                  readOnly={formData.taxType !== TaxType.TAXABLE}
                  className={formData.taxType === TaxType.TAXABLE ? "" : "bg-slate-900/50 text-slate-400 cursor-not-allowed"}
                />
                 <Input
                  id="total"
                  name="total"
                  type="number"
                  label="總金額 (含稅)"
                  value={formData.total}
                  readOnly
                  className="bg-slate-900/50 font-bold text-emerald-400 cursor-not-allowed"
                />
              </div>

              {isRiskyCategory && formData.taxType === TaxType.TAXABLE && Number(formData.tax) > 0 && (
                 <div className="animate-in fade-in slide-in-from-top-2">
                   <div className="bg-amber-500/10 border border-amber-500/20 rounded-lg p-3 text-amber-300 text-sm flex gap-3 items-start">
                     <ShieldAlert className="w-5 h-5 shrink-0 mt-0.5" />
                     <div className="space-y-2 flex-1">
                       <p className="font-bold">會計師提醒：此類別稅額通常「不可扣抵」</p>
                       <p className="opacity-80 text-xs">營業稅法規定，交際費與職工福利(含伙食)之進項稅額不得扣抵。建議將稅額設為 0 (併入成本)。</p>
                       <Button 
                         type="button" 
                         variant="secondary" 
                         size="sm" 
                         className="w-full text-xs bg-amber-500/20 hover:bg-amber-500/30 text-amber-200 border-amber-500/20"
                         onClick={makeTaxNonDeductible}
                       >
                         一鍵調整：稅額歸零 (併入成本)
                       </Button>
                     </div>
                   </div>
                 </div>
              )}
            </div>
          </Card>

          <Card className="p-6 space-y-4 md:col-span-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                     <h3 className="text-slate-400 font-semibold text-sm uppercase tracking-wider mb-2">
                      帳務歸屬
                    </h3>
                    <div className="relative">
                        <Label htmlFor="category" required>會計科目</Label>
                        <select
                            id="category"
                            name="category"
                            value={formData.category}
                            onChange={handleChange}
                            required
                            className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2.5 pl-3 pr-8 text-slate-100 focus:outline-none focus:ring-2 focus:ring-sky-500 mt-1 appearance-none group"
                        >
                            <option value="" disabled>-- 請選擇類別 --</option>
                            {CATEGORY_GROUPS.map((group) => (
                              <optgroup key={group.groupLabel} label={group.groupLabel} className="bg-slate-900">
                                {group.items.map((item) => (
                                  <option key={item.value} value={item.value}>
                                    {item.label}
                                  </option>
                                ))}
                              </optgroup>
                            ))}
                        </select>
                        <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none text-slate-500 mt-6">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" />
                          </svg>
                        </div>
                    </div>
                </div>

                <div className="space-y-4">
                    <h3 className="text-slate-400 font-semibold text-sm uppercase tracking-wider mb-2">
                      備註說明
                    </h3>
                    <div>
                        <Label htmlFor="note">備註</Label>
                        <input
                            id="note"
                            name="note"
                            value={formData.note}
                            onChange={handleChange}
                            placeholder="如：購買電腦、固定資產..."
                            className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2.5 px-3 text-slate-100 focus:outline-none focus:ring-2 focus:ring-sky-500 mt-1"
                        />
                    </div>
                </div>
            </div>
          </Card>
        </div>

        <div className="fixed bottom-0 left-0 right-0 p-4 bg-slate-950/80 backdrop-blur-md border-t border-slate-800 z-40 safe-area-bottom">
            <div className="max-w-4xl mx-auto flex flex-col md:flex-row items-center gap-4">
                <Button 
                    type="submit" 
                    className="w-full md:w-auto md:flex-1 py-3 text-lg font-bold shadow-lg shadow-sky-900/20"
                    isLoading={loading}
                    icon={Save}
                >
                    確認送出
                </Button>

                <Button 
                    type="button" 
                    variant="ghost" 
                    onClick={() => setFormData(INITIAL_FORM_STATE)}
                    icon={RotateCcw}
                    disabled={loading}
                    className="w-full md:w-auto"
                >
                    重置
                </Button>

                {message && (
                    <div className={`w-full md:w-auto flex-1 px-4 py-2 rounded-lg text-sm font-medium flex flex-col justify-center animate-in fade-in slide-in-from-bottom-2 ${
                        message.type === 'success' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'bg-rose-500/10 text-rose-400 border border-rose-500/20'
                    }`}>
                        <div className="flex items-center mb-1">
                            {message.type === 'error' && <WifiOff className="w-4 h-4 mr-2" />}
                            <span className="font-bold">{message.text}</span>
                        </div>
                        {message.detail && (
                            <div className="text-xs mt-1 text-rose-300/90 pl-6 leading-relaxed">
                                {message.detail}
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
      </form>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { Camera, Loader2, Sparkles, X, ScanLine, Upload } from 'lucide-react';
import { FLATTENED_CATEGORY_VALUES } from '../constants.ts';

interface ScannerProps {
  onScanResult: (data: any) => void;
  onClose: () => void;
}

export const Scanner: React.FC<ScannerProps> = ({ onScanResult, onClose }) => {
  const [loading, setLoading] = useState(false);
  const [cameraActive, setCameraActive] = useState(false);
  const [cameraError, setCameraError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    return () => {
      stopCamera();
    };
  }, []);

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
    setCameraActive(false);
    setCameraError(null);
  };

  const startCamera = async () => {
    try {
      setCameraError(null);
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          facingMode: 'environment',
          width: { ideal: 1920 },
          height: { ideal: 1080 } 
        } 
      });

      setCameraActive(true);

      setTimeout(async () => {
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          try {
             await videoRef.current.play();
          } catch (e) {
             console.error("Video play error:", e);
          }
        }
      }, 100);

    } catch (err: any) {
      console.error("Camera access error:", err);
      setCameraError("無法存取相機，請檢查瀏覽器權限或使用 HTTPS。");
    }
  };

  const captureImage = () => {
    if (!videoRef.current || !canvasRef.current) return;

    const video = videoRef.current;
    const canvas = canvasRef.current;

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;

    const context = canvas.getContext('2d');
    if (context) {
      context.drawImage(video, 0, 0, canvas.width, canvas.height);
      const base64Data = canvas.toDataURL('image/jpeg', 0.8).split(',')[1];
      stopCamera();
      processImage(base64Data);
    }
  };

  const processImage = async (base64Data: string) => {
    setLoading(true);
    try {
      if (!process.env.API_KEY) {
        throw new Error("Missing API_KEY in environment variables.");
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const categoryList = FLATTENED_CATEGORY_VALUES.join('", "');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          {
            parts: [
              { inlineData: { mimeType: 'image/jpeg', data: base64Data } },
              { 
                text: `
                You are an expert accountant for a Taiwan one-person company. 
                Analyze this invoice image and extract data strictly following Taiwan VAT regulations.

                Tasks:
                1. Identify if it is an "Input" (Expense) or "Output" (Sales) invoice.
                2. Extract the Date, Invoice Number, and Seller Tax ID.
                3. Extract the Amount (Sales Amount excluding tax).
                4. Extract the Tax (5% VAT).
                5. Extract the Total (Amount + Tax).
                6. Suggest the most appropriate accounting category from this list: ["${categoryList}"].
                7. Determine Format Code: 
                   - If it's a thermal paper with Tax ID (E-Invoice), use '25'. 
                   - If it's a traditional A4/half-sheet triplicate, use '21'.

                Rules:
                - Date format must be YYYY-MM-DD. Convert ROC years (115 -> 2026).
                - Amount, Tax, and Total should be numbers.
                - If specific fields are not found, leave them null.
                `
              }
            ]
          }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, enum: ["Input", "Output"] },
              formatCode: { type: Type.STRING },
              date: { type: Type.STRING, description: "YYYY-MM-DD" },
              invoiceNo: { type: Type.STRING },
              taxId: { type: Type.STRING },
              amount: { type: Type.NUMBER },
              tax: { type: Type.NUMBER },
              total: { type: Type.NUMBER },
              category: { type: Type.STRING }
            },
            required: ["type", "date", "amount", "total"]
          }
        }
      });

      let text = response.text || '{}';
      if (text.startsWith('```')) {
        text = text.replace(/^```(json)?\n/, '').replace(/\n```$/, '');
      }

      const result = JSON.parse(text);
      console.log("AI Scan Result:", result);
      onScanResult(result);

    } catch (error) {
      console.error("AI Scan Error:", error);
      alert(`掃描辨識失敗: ${error instanceof Error ? error.message : '未知錯誤'}`);
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      alert("圖片過大，請使用小於 5MB 的照片");
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      processImage(base64);
    };
    reader.readAsDataURL(file);
  };

  return (
    <>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-md animate-in fade-in duration-200">
        <div className="w-full max-w-sm bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-2xl relative overflow-hidden">
          <canvas ref={canvasRef} className="hidden" />

          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-sky-500 via-purple-500 to-emerald-500" />

          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-bold flex items-center text-white">
              <ScanLine className="w-5 h-5 mr-2 text-sky-400" />
              AI 智慧憑證掃描
            </h3>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-800 text-slate-400 hover:text-white transition-colors">
              <X size={20} />
            </button>
          </div>

          <div className="space-y-4">
            {loading ? (
               <div className="w-full h-48 rounded-xl border-2 border-dashed border-sky-500/50 bg-sky-500/5 flex flex-col items-center justify-center space-y-3">
                  <Loader2 className="w-10 h-10 animate-spin text-sky-400" />
                  <p className="text-sm text-sky-300 font-medium animate-pulse">正在分析憑證...</p>
               </div>
            ) : (
              <div className="grid grid-cols-2 gap-4">
                  <button
                      onClick={startCamera}
                      className="flex flex-col items-center justify-center h-32 rounded-xl bg-slate-800 border border-slate-700 hover:bg-slate-700 hover:border-sky-500/50 transition-all group"
                  >
                      <div className="p-3 rounded-full bg-slate-900 group-hover:bg-sky-500 group-hover:text-white text-sky-400 mb-2 transition-colors">
                          <Camera className="w-6 h-6" />
                      </div>
                      <span className="text-sm font-medium text-slate-300">開啟相機</span>
                  </button>

                  <button
                      onClick={() => fileInputRef.current?.click()}
                      className="flex flex-col items-center justify-center h-32 rounded-xl bg-slate-800 border border-slate-700 hover:bg-slate-700 hover:border-emerald-500/50 transition-all group"
                  >
                      <div className="p-3 rounded-full bg-slate-900 group-hover:bg-emerald-500 group-hover:text-white text-emerald-400 mb-2 transition-colors">
                          <Upload className="w-6 h-6" />
                      </div>
                      <span className="text-sm font-medium text-slate-300">上傳圖片</span>
                  </button>
              </div>
            )}

            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileUpload} 
            />

            {cameraError && (
                <div className="text-xs text-rose-400 bg-rose-500/10 p-2 rounded text-center">
                    {cameraError}
                </div>
            )}

            <div className="bg-slate-800/50 rounded-lg p-3 text-xs text-slate-400 leading-relaxed border border-slate-700/50">
              <p className="flex items-start gap-2">
                <Sparkles className="w-3 h-3 mt-0.5 text-yellow-400 shrink-0" />
                AI 將自動辨識：進銷別、日期、統編、金額與科目。
              </p>
            </div>
          </div>
        </div>
      </div>

      {cameraActive && (
        <div className="fixed inset-0 z-[100] bg-black flex flex-col animate-in fade-in duration-300">
          <div className="absolute top-0 left-0 right-0 p-6 z-20 flex justify-between items-start bg-gradient-to-b from-black/80 to-transparent pb-12">
             <div className="px-4 py-2 bg-black/40 backdrop-blur-md rounded-full text-white text-sm font-medium border border-white/10">
                拍攝收據 / 發票
             </div>
             <button 
               onClick={stopCamera} 
               className="p-3 bg-black/40 hover:bg-slate-800 text-white rounded-full backdrop-blur-md transition-all border border-white/10"
             >
               <X size={24} />
             </button>
          </div>

          <div className="relative flex-1 bg-black overflow-hidden flex items-center justify-center">
              <video 
                ref={videoRef} 
                autoPlay 
                playsInline 
                muted
                className="absolute w-full h-full object-cover"
              />
              <div className="relative w-[85%] aspect-[3/4] max-w-md border-2 border-white/30 rounded-2xl shadow-[0_0_0_9999px_rgba(0,0,0,0.5)] pointer-events-none">
                  <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-sky-500 -mt-0.5 -ml-0.5 rounded-tl-xl" />
                  <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-sky-500 -mt-0.5 -mr-0.5 rounded-tr-xl" />
                  <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-sky-500 -mb-0.5 -ml-0.5 rounded-bl-xl" />
                  <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-sky-500 -mb-0.5 -mr-0.5 rounded-br-xl" />
                  <div className="absolute inset-0 flex items-center justify-center opacity-30">
                     <ScanLine className="w-16 h-16 text-white animate-pulse" />
                  </div>
              </div>
          </div>

          <div className="h-32 bg-black flex items-center justify-center relative z-20 pt-2 pb-8">
               <button 
                  onClick={captureImage}
                  className="group relative w-20 h-20 flex items-center justify-center touch-manipulation"
               >
                   <div className="absolute inset-0 bg-white rounded-full opacity-20 group-hover:scale-110 transition-transform duration-300" />
                   <div className="relative w-16 h-16 bg-white rounded-full border-[3px] border-slate-900 ring-4 ring-white shadow-xl group-active:scale-95 transition-transform duration-100" />
               </button>
          </div>
        </div>
      )}
    </>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Save, 
  RotateCcw, 
  FileText, 
  Hash, 
  DollarSign, 
  Calendar,
  Sparkles,
  CheckCircle2,
  AlertTriangle,
  WifiOff,
  ExternalLink,
  Table2,
  History,
  ShieldAlert
} from 'lucide-react';
import { 
  InvoiceType, 
  TaxType, 
  InvoiceFormState, 
  AppConfig, 
  ApiResponse 
} from '../types.ts';
import { 
  INITIAL_FORM_STATE, 
  FORMAT_CODE_OPTIONS, 
  CATEGORY_GROUPS, 
  TAX_TYPE_OPTIONS 
} from '../constants.ts';
import { Card, Input, Select, Button, Label } from './UI.tsx';
import { isValidTaiwanTaxId } from '../utils/validation.ts';
import { Scanner } from './Scanner.tsx';

interface InvoiceFormProps {
  config: AppConfig;
  onLogout: () => void;
}

const LAST_SCAN_KEY = 'last_scanned_invoice';
const RISKY_CATEGORIES = ['伙食費', '交際費', '職工福利'];

export const InvoiceForm: React.FC<InvoiceFormProps> = ({ config, onLogout }) => {
  const [formData, setFormData] = useState<InvoiceFormState>(INITIAL_FORM_STATE);
  const [loading, setLoading] = useState(false);
  const [showScanner, setShowScanner] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string; detail?: React.ReactNode } | null>(null);
  const [hasLastScan, setHasLastScan] = useState(false);
  const [isTaxManuallyEdited, setIsTaxManuallyEdited] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem(LAST_SCAN_KEY);
    if (saved) {
      setHasLastScan(true);
    }
  }, []);

  const calculateTotals = useCallback(() => {
    // Stop auto-calc if tax was manually set to 0 (to allow non-deductible logic)
    // or if the user manually corrected the tax to fix rounding issues.
    if (isTaxManuallyEdited) return;

    if (formData.amount === '' || formData.taxType !== TaxType.TAXABLE) return;
    const amount = Number(formData.amount);
    const tax = Math.round(amount * 0.05);
    const total = amount + tax;

    setFormData(prev => {
        if (prev.tax === tax && prev.total === total) return prev;
        return { ...prev, tax, total };
    });
  }, [formData.amount, formData.taxType, isTaxManuallyEdited]);

  useEffect(() => {
    if (formData.amount !== '' && formData.taxType === TaxType.TAXABLE) {
       calculateTotals();
    } else if (formData.taxType === TaxType.ZERO_RATE || formData.taxType === TaxType.TAX_FREE) {
        const amount = Number(formData.amount || 0);
        setFormData(prev => ({ ...prev, tax: 0, total: amount }));
    }
  }, [formData.amount, formData.taxType, calculateTotals]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;

    // Reset manual tax edit flag if user changes base amount, triggers auto-calc
    if (name === 'amount') {
      setIsTaxManuallyEdited(false);
    }

    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleTaxChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newTax = Number(e.target.value);
    setIsTaxManuallyEdited(true); // Flag as manual so auto-calc doesn't revert it

    setFormData(prev => {
      // Allow manual tax adjustment to update the Total (fixing the $220 vs $221 issue)
      const currentAmount = typeof prev.amount === 'number' ? prev.amount : 0;
      return { 
        ...prev, 
        tax: newTax,
        total: currentAmount + newTax
      };
    });
  };

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newType = e.target.value as InvoiceType;
    const firstFormatCode = FORMAT_CODE_OPTIONS[newType][0].value;
    setFormData(prev => ({ 
      ...prev, 
      type: newType, 
      formatCode: firstFormatCode 
    }));
  };

  const makeTaxNonDeductible = () => {
    // Expert Logic: Merge Tax into Sales Amount (Cost), Set Tax to 0.
    const currentTotal = Number(formData.total || 0);
    setFormData(prev => ({
        ...prev,
        amount: currentTotal, // The cost is now the full price
        tax: 0,
        total: currentTotal, // Explicitly set total to ensure consistency
        taxType: TaxType.TAXABLE // Keep as taxable so we know it had tax, but amount is 0
    }));
    setIsTaxManuallyEdited(true);
  };

  const populateFormData = (data: any) => {
    console.log("Populating Form Data:", data);

    // Robust Type Detection
    const typeStr = (data.type || '').toLowerCase();
    const newType = (typeStr.includes('output') || typeStr.includes('sales')) 
        ? InvoiceType.OUTPUT 
        : InvoiceType.INPUT;

    // Robust Format Code
    let newFormatCode = data.formatCode;
    const validCodes = FORMAT_CODE_OPTIONS[newType].map(o => o.value);
    if (!validCodes.includes(newFormatCode)) {
      newFormatCode = validCodes[0]; 
      if (newType === InvoiceType.INPUT && data.taxId && FORMAT_CODE_OPTIONS[InvoiceType.INPUT].some(o => o.value === '25')) {
          newFormatCode = '25';
      }
    }

    let newDate = data.date || '';
    newDate = newDate.replace(/\//g, '-');

    const parseNumber = (val: any) => {
        if (typeof val === 'number') return val;
        if (typeof val === 'string') {
            const num = parseFloat(val.replace(/,/g, ''));
            return isNaN(num) ? '' : num;
        }
        return '';
    };

    const newAmount = parseNumber(data.amount);
    const newTax = parseNumber(data.tax);
    const newTotal = parseNumber(data.total);

    setFormData(prev => ({
      ...prev,
      type: newType,
      formatCode: newFormatCode,
      date: newDate || prev.date,
      invoiceNo: data.invoiceNo || prev.invoiceNo,
      taxId: data.taxId || prev.taxId,
      amount: newAmount,
      tax: newTax,
      total: newTotal,
      category: data.category || prev.category,
      note: data.note || prev.note || '',
    }));

    // Critical Fix: If the Scanner's Tax doesn't match the 5% Calculation (due to rounding differences),
    // we must treat it as "Manually Edited" to prevent calculateTotals() from overwriting 
    // the correct Total (e.g. 220) with a calculated Total (e.g. 221).
    if (typeof newAmount === 'number' && typeof newTax === 'number') {
        const calculatedTax = Math.round(newAmount * 0.05);
        if (newTax !== calculatedTax) {
            console.log(`Rounding Mismatch Detected: Scanner Tax ${newTax} vs Calc ${calculatedTax}. Trusting Scanner.`);
            setIsTaxManuallyEdited(true);
        } else {
            setIsTaxManuallyEdited(false);
        }
    } else {
        setIsTaxManuallyEdited(false);
    }
  };

  const handleScanResult = (data: any) => {
    localStorage.setItem(LAST_SCAN_KEY, JSON.stringify(data));
    setHasLastScan(true);

    populateFormData(data);
    setShowScanner(false);

    const amountFound = data.amount ? `金額 $${data.amount}` : '未偵測到金額';
    setMessage({ 
        type: 'success', 
        text: `AI 辨識完成！`, 
        detail: `已填入：${amountFound}、${data.category || '無建議科目'}。請務必核對。` 
    });
  };

  const restoreLastScan = () => {
    try {
      const saved = localStorage.getItem(LAST_SCAN_KEY);
      if (saved) {
        const data = JSON.parse(saved);
        populateFormData(data);
        setMessage({ type: 'success', text: '已載入上一次的掃描資料。' });
      }
    } catch (e) {
      console.error("Failed to restore scan", e);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);

    // Validation
    if (!formData.amount) {
      setMessage({ type: 'error', text: '請輸入銷售額' });
      setLoading(false);
      return;
    }
    if (!formData.category) {
      setMessage({ type: 'error', text: '請選擇會計科目' });
      setLoading(false);
      return;
    }

    const isTriplicate = ['21', '31'].includes(formData.formatCode);
    if (isTriplicate && !formData.taxId) {
        setMessage({ type: 'error', text: '三聯式發票必須輸入統編 (Tax ID)' });
        setLoading(false);
        return;
    }
    if (formData.taxId && !isValidTaiwanTaxId(formData.taxId)) {
        setMessage({ type: 'error', text: '統編格式錯誤', detail: '請檢查 8 碼統編是否正確' });
        setLoading(false);
        return;
    }

    // Mapping for Google Sheet
    const TYPE_MAPPING = {
      [InvoiceType.INPUT]: '進項 (支出)',
      [InvoiceType.OUTPUT]: '銷項 (收入)',
    };

    const TAX_TYPE_LABEL_MAP: Record<string, string> = {
        '1': '1 - 應稅', 
        '2': '2 - 零稅率', 
        '3': '3 - 免稅'
    };

    // Correct 1-to-1 Mapping to match the Sheet columns
    const payload = {
      action: 'submit',
      secret: config.apiSecret,
      userEmail: config.userEmail,
      date: formData.date,
      type: TYPE_MAPPING[formData.type], 
      formatCode: formData.formatCode,
      invoiceNo: formData.invoiceNo,
      taxId: formData.taxId,
      amount: Number(formData.amount),
      tax: Number(formData.tax),
      total: Number(formData.total),
      taxType: TAX_TYPE_LABEL_MAP[formData.taxType],
      category: formData.category,
      note: formData.note,
    };

    try {
      const response = await fetch(config.scriptUrl, {
        method: 'POST',
        mode: 'cors',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify(payload),
        redirect: 'follow',
      });

      if (!response.ok) {
        throw new Error(`伺服器回應錯誤: ${response.status}`);
      }

      const text = await response.text();
      let result: ApiResponse;
      try {
        result = JSON.parse(text);
      } catch (e) {
        throw new Error("伺服器回傳格式錯誤 (非 JSON)");
      }

      if (result.status === 'success') {
        setMessage({ type: 'success', text: `成功錄入! (Row: ${result.row})` });
        setFormData(prev => ({
          ...INITIAL_FORM_STATE,
          date: prev.date,
          type: prev.type,
          formatCode: prev.formatCode,
        }));
        setIsTaxManuallyEdited(false);
      } else {
        throw new Error(result.message || 'Unknown error');
      }
    } catch (error: any) {
      console.error("Submission Error:", error);
      setMessage({ type: 'error', text: error.message });
    } finally {
      setLoading(false);
    }
  };

  const isTaxIdValid = formData.taxId === '' || isValidTaiwanTaxId(formData.taxId);
  const isRiskyCategory = RISKY_CATEGORIES.some(c => formData.category.includes(c));

  return (
    <div className="max-w-4xl mx-auto pb-24">
      {showScanner && <Scanner onScanResult={handleScanResult} onClose={() => setShowScanner(false)} />}

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
              新增憑證
              <span className="text-xs font-normal px-2 py-0.5 rounded bg-slate-800 text-slate-400 border border-slate-700">2026 帳期</span>
            </h2>
            <p className="text-slate-400 text-sm">{config.userEmail}</p>
        </div>
        <div className="flex items-center gap-2 w-full md:w-auto">
          {config.sheetUrl && (
            <a 
              href={config.sheetUrl} 
              target="_blank" 
              rel="noopener noreferrer"
              className="flex-1 md:flex-none inline-flex items-center justify-center px-3 py-1.5 text-sm font-medium text-sky-400 bg-sky-950/50 border border-sky-900/50 rounded-lg hover:bg-sky-900/50 transition-colors"
            >
              <Table2 size={14} className="mr-2" />
              查看報表
              <ExternalLink size={12} className="ml-1 opacity-50" />
            </a>
          )}
          <Button variant="ghost" onClick={onLogout} size="sm" className="flex-1 md:flex-none">登出</Button>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <Card className="p-6 space-y-4">
            <div className="flex justify-between items-center mb-2">
              <h3 className="text-sky-400 font-semibold text-sm uppercase tracking-wider flex items-center">
                <FileText className="w-4 h-4 mr-2" />
                憑證分類
              </h3>
              <div className="flex gap-2">
                {hasLastScan && (
                   <Button 
                    type="button" 
                    variant="ghost" 
                    size="sm" 
                    className="h-8 text-xs text-slate-400 hover:text-white"
                    onClick={restoreLastScan}
                    title="載入上一次掃描的資料"
                  >
                    <History size={14} className="mr-1.5" />
                    載入上次
                  </Button>
                )}
                <Button 
                  type="button" 
                  variant="secondary" 
                  size="sm" 
                  className="h-8 text-xs bg-sky-500/10 hover:bg-sky-500/20 text-sky-400 border-sky-500/20"
                  onClick={() => setShowScanner(true)}
                >
                  <Sparkles size={14} className="mr-1.5" />
                  AI 掃描
                </Button>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <Select
                id="type"
                name="type"
                label="進銷別"
                value={formData.type}
                onChange={handleTypeChange}
                options={[
                  { value: InvoiceType.INPUT, label: '進項 (支出)' },
                  { value: InvoiceType.OUTPUT, label: '銷項 (收入)' },
                ]}
              />
              <Input
                id="date"
                name="date"
                type="date"
                label="日期"
                value={formData.date}
                onChange={handleChange}
                required
                icon={Calendar}
              />
            </div>

            <Select
              id="formatCode"
              name="formatCode"
              label="格式代號"
              value={formData.formatCode}
              onChange={handleChange}
              options={FORMAT_CODE_OPTIONS[formData.type]}
            />

            <div className="grid grid-cols-2 gap-4">
              <Input
                id="invoiceNo"
                name="invoiceNo"
                label="發票號碼"
                placeholder="AA12345678"
                value={formData.invoiceNo}
                onChange={(e) => setFormData(prev => ({...prev, invoiceNo: e.target.value.toUpperCase()}))}
                maxLength={10}
                required
                icon={Hash}
              />
              <div className="relative">
                <Input
                  id="taxId"
                  name="taxId"
                  label="對方統編"
                  placeholder="8位數字"
                  value={formData.taxId}
                  onChange={handleChange}
                  maxLength={8}
                  error={!isTaxIdValid ? "統編邏輯錯誤" : ""}
                  required={['21', '31'].includes(formData.formatCode)}
                />
                 {isTaxIdValid && formData.taxId.length === 8 && (
                   <CheckCircle2 className="absolute top-9 right-3 text-emerald-500 w-4 h-4 animate-in zoom-in" />
                )}
              </div>
            </div>
          </Card>

          <Card className="p-6 space-y-4">
            <h3 className="text-emerald-400 font-semibold text-sm uppercase tracking-wider mb-2 flex items-center">
              <DollarSign className="w-4 h-4 mr-2" />
              金額明細
            </h3>

             <Select
              id="taxType"
              name="taxType"
              label="課稅別"
              value={formData.taxType}
              onChange={handleChange}
              options={TAX_TYPE_OPTIONS}
            />

            <div className="space-y-4">
              <Input
                id="amount"
                name="amount"
                type="number"
                label="銷售額 (未稅)"
                placeholder="0"
                value={formData.amount}
                onChange={handleChange}
                required
                icon={DollarSign}
                className="font-mono text-xl tracking-tight"
              />

              <div className="grid grid-cols-2 gap-4">
                 <Input
                  id="tax"
                  name="tax"
                  type="number"
                  label="營業稅額 (5%)"
                  value={formData.tax}
                  onChange={handleTaxChange}
                  readOnly={formData.taxType !== TaxType.TAXABLE}
                  className={formData.taxType === TaxType.TAXABLE ? "" : "bg-slate-900/50 text-slate-400 cursor-not-allowed"}
                />
                 <Input
                  id="total"
                  name="total"
                  type="number"
                  label="總金額 (含稅)"
                  value={formData.total}
                  readOnly
                  className="bg-slate-900/50 font-bold text-emerald-400 cursor-not-allowed"
                />
              </div>

              {isRiskyCategory && formData.taxType === TaxType.TAXABLE && Number(formData.tax) > 0 && (
                 <div className="animate-in fade-in slide-in-from-top-2">
                   <div className="bg-amber-500/10 border border-amber-500/20 rounded-lg p-3 text-amber-300 text-sm flex gap-3 items-start">
                     <ShieldAlert className="w-5 h-5 shrink-0 mt-0.5" />
                     <div className="space-y-2 flex-1">
                       <p className="font-bold">會計師提醒：此類別稅額通常「不可扣抵」</p>
